BEGIN;
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (19, 7, 'en', 'Architecture of Xi''an City Wall', 'See the picture and read about the magnificent architecture of Xi''an''s ancient city wall — discover the majesty of ancient Chinese defensive design and construction techniques.', 'Read More', 'Visual Interactive', NULL, '2026-04-17 13:56:54.312691+08', '2026-04-17 21:36:46.703756+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (32, 11, 'zh', '苏州九曲桥', '探索苏州园林中传统九曲桥的设计与建造方式。了解其曲折的形状、木质结构、石质支撑以及在水上的布局，如何将美感、平衡与功能融为一体，体现中国古典建筑的魅力。', '阅读更多', '视觉互动', NULL, '2026-04-17 13:57:01.674769+08', '2026-04-17 21:36:55.687664+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (33, 11, 'ar', 'جسر سوتشو المتعرج', 'استكشف كيفية تصميم وبناء الجسر المتعرج التقليدي في حدائق سوتشو. تعرف على كيفية دمج شكله والهيكل الخشبي والدعامات الحجرية والموضع فوق المياه جمالاً وتوازناً ووظيفة في العمارة الكلاسيكية الصينية.', 'قراءة المزيد', 'تفاعل بصري', NULL, '2026-04-17 13:57:01.812664+08', '2026-04-17 21:36:55.735612+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (22, 8, 'en', 'Chinese Bracket System', 'The Dǒugǒng (斗拱) — China''s Most Ingenious Invention in Architecture. This interlocking bracket system, found on the gate towers of Xi''an''s city wall, was engineered without a single nail and has endured for over 650 years.', 'Read More', 'Visual Interactive', NULL, '2026-04-17 13:56:55.032362+08', '2026-04-17 21:38:13.332059+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (20, 7, 'zh', '西安城墙建筑', '欣赏图片，深入了解西安古城墙的宏伟建筑，探索中国古代防御工事设计与建造技艺的壮美。', '阅读更多', '视觉互动', NULL, '2026-04-17 13:56:54.577774+08', '2026-04-17 21:36:46.731096+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (21, 7, 'ar', 'هندسة سور مدينة شيان', 'شاهد الصورة واقرأ عن الهندسة المعمارية المذهلة لسور مدينة شيان القديمة، واكتشف عظمة تقنيات التصميم والبناء الدفاعية الصينية القديمة.', 'قراءة المزيد', 'تفاعل بصري', NULL, '2026-04-17 13:56:54.890682+08', '2026-04-17 21:36:46.757966+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (31, 11, 'en', 'Suzhou Zigzag Bridge', 'Explore how the traditional zigzag bridge was designed and built in Suzhou gardens. Learn how its shape, wooden structure, stone supports, and placement over water combine beauty, balance, and function in classical Chinese architecture.', 'Read More', 'Visual Interactive', NULL, '2026-04-17 13:57:01.54117+08', '2026-04-17 21:36:55.657281+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (24, 8, 'ar', 'نظام الدوجونغ الصيني', 'الدوجونغ (斗拱) — أروع اختراع في الهندسة المعمارية الصينية. هذا النظام المتشابك من الدعامات الموجود في أبراج بوابات سور شيان صُمّم دون مسمار واحد وصمد أكثر من 650 عاماً.', 'قراءة المزيد', 'تفاعل بصري', NULL, '2026-04-17 13:56:55.302852+08', '2026-04-17 21:38:13.402006+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (27, 9, 'ar', 'اكتشف عجائب العمارة', 'استكشف التفاصيل الدقيقة والعناصر الرمزية التي تجعل العمارة القديمة في شيان رائعة حقاً — من تماثيل أبراج البوابات الحارسة إلى الملاط الأسطوري من الأرز اللزج.', 'قراءة المزيد', NULL, 'استكشف التماثيل', '2026-04-17 13:56:56.362985+08', '2026-04-17 21:31:06.037094+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (23, 8, 'zh', '中国斗拱系统', '斗拱——中国建筑中最精巧的发明。这种层层咬合的结构体系出现在西安城门楼上，全程不用一颗钉子，历经六百五十年风雨依然坚固。', '阅读更多', '视觉互动', NULL, '2026-04-17 13:56:55.163035+08', '2026-04-17 21:38:13.36116+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (2, 1, 'zh', '故宫建筑', '欣赏图片，深入了解中国皇家宫殿的宏伟建筑，探索中国古代设计与建造技艺的壮美。', '阅读更多', '视觉互动', NULL, '2026-04-17 13:50:57.977938+08', '2026-04-17 21:34:25.318776+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (25, 9, 'en', 'Discover Architectural Marvels', 'Explore the intricate details and symbolic elements that make Xi''an''s ancient architecture truly remarkable — from guardian roof statues on gate towers to the legendary sticky-rice mortar.', 'Read More', NULL, 'Explore Statues', '2026-04-17 13:56:55.919886+08', '2026-04-17 21:31:05.963162+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (26, 9, 'zh', '探索建筑奇迹', '探索那些令西安古建筑举世无双的精巧细节与象征元素——从城门楼屋脊上的守护神兽到传说中以糯米汁砌成的千年古墙。', '阅读更多', NULL, '探索神兽', '2026-04-17 13:56:56.220312+08', '2026-04-17 21:31:05.989525+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (29, 10, 'zh', '苏州园林建筑', '欣赏图片，探索苏州园林优雅的建筑风格——在这里，墙体、庭院、月洞门、水景和木结构被精心布局，营造出自然与设计之间的和谐。', '阅读更多', '视觉互动', NULL, '2026-04-17 13:57:01.269638+08', '2026-04-17 21:36:30.500401+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (30, 10, 'ar', 'الخطط المعمارية لحديقة سوتشو', 'شاهد الصورة واستكشف العمارة الأنيقة لحدائق سوتشو — حيث تُرتّب الجدران والأفنية وأبواب القمر والمياه والهياكل الخشبية بعناية لخلق التوازن بين الطبيعة والتصميم.', 'قراءة المزيد', 'تفاعل بصري', NULL, '2026-04-17 13:57:01.402744+08', '2026-04-17 21:36:30.547559+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (8, 3, 'zh', '探索建筑奇迹', '探索那些令中国建筑举世无双的精巧细节与象征元素——从守护屋脊的神兽到流传千年的装饰纹样。', '阅读更多', NULL, '探索神兽', '2026-04-17 13:50:59.028193+08', '2026-04-17 20:31:19.649761+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (9, 3, 'ar', 'اكتشف عجائب العمارة', 'استكشف التفاصيل الدقيقة والعناصر الرمزية التي تجعل العمارة الصينية رائعة حقاً — من تماثيل السقف الحارسة إلى الأنماط الزخرفية المتوارثة عبر آلاف السنين.', 'قراءة المزيد', NULL, 'استكشف التماثيل', '2026-04-17 13:50:59.168048+08', '2026-04-17 20:31:19.677663+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (3, 1, 'ar', 'عمارة المدينة المحرمة', 'شاهد الصورة واقرأ عن الهندسة المعمارية المذهلة للقصور الإمبراطورية الصينية، واكتشف عظمة تقنيات التصميم والبناء الصينية القديمة.', 'قراءة المزيد', 'تفاعل بصري', NULL, '2026-04-17 13:50:58.116202+08', '2026-04-17 21:34:25.346576+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (7, 3, 'en', 'Discover Architectural Marvels', 'Explore the intricate details and symbolic elements that make Chinese architecture truly remarkable — from guardian roof statues to decorative patterns passed down through thousands of years.', 'Read More', NULL, 'Explore Statues', '2026-04-17 13:50:58.902923+08', '2026-04-17 20:31:19.60347+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (4, 2, 'en', 'Chinese Bracket System', 'The Dǒugǒng (斗拱) — China''s Most Ingenious Invention in Architecture. If there is one thing that makes Chinese imperial architecture unique in the entire world, it is the dǒugǒng. This interlocking bracket system, found on every major hall of the Forbidden City, was engineered without a single nail.', 'Read More', 'Visual Interactive', NULL, '2026-04-17 13:50:58.24797+08', '2026-04-17 21:35:32.149329+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (5, 2, 'zh', '中国斗拱系统', '斗拱（斗拱）——中国建筑中最精巧的发明。如果说有什么让中国皇家建筑在世界上独一无二，那就是斗拱。这种层层咬合的结构体系出现在故宫每一座主要殿宇上，且全程不用一颗钉子。', '阅读更多', '视觉互动', NULL, '2026-04-17 13:50:58.653803+08', '2026-04-17 21:35:32.179598+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (34, 12, 'en', 'Suzhou Garden Windows', 'Discover the unique windows of Suzhou gardens — known for their intricate shapes and artistic designs. These windows are not just for light; they frame nature like paintings, creating changing views of gardens, water, and architecture from every angle.', 'Read More', NULL, 'Explore Windows', '2026-04-17 13:57:01.944952+08', '2026-04-17 21:16:37.693869+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (35, 12, 'zh', '苏州园林窗户', '探索苏州园林独特的窗户——以其精美的形状和艺术设计而闻名。这些窗户不仅用于采光，还如同画框一般，将自然景色定格成画，从不同角度呈现园林、水景与建筑的变化之美。', '阅读更多', NULL, '探索窗户艺术', '2026-04-17 13:57:02.078352+08', '2026-04-17 21:16:37.739524+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (36, 12, 'ar', 'نوافذ حدائق سوتشو', 'اكتشف النوافذ الفريدة لحدائق سوتشو — المعروفة بأشكالها المعقدة وتصميماتها الفنية. هذه النوافذ لا تقتصر على الإضاءة؛ فهي تُأطّر الطبيعة كاللوحات، خالقةً مناظر متغيرة للحدائق والمياه والعمارة من كل زاوية.', 'قراءة المزيد', NULL, 'استكشف نوافذ الحدائق', '2026-04-17 13:57:02.212658+08', '2026-04-17 21:16:37.767843+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (1, 1, 'en', 'Architecture of the Forbidden City', 'See the picture and read about the magnificent architecture of China''s imperial palace, discover the majesty of ancient Chinese design and construction techniques.', 'Read More', 'Visual Interactive', NULL, '2026-04-17 13:50:57.828144+08', '2026-04-17 21:34:25.276359+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (6, 2, 'ar', 'نظام الدوجونغ الصيني', 'الدوجونغ (斗拱) — أروع اختراع في الهندسة المعمارية الصينية. إذا كان هناك شيء يجعل الهندسة المعمارية الإمبراطورية الصينية فريدة في العالم بأسره، فهو الدوجونغ. هذا النظام المتشابك من الأقواس الموجود في كل قاعة رئيسية في المدينة المحرمة، صُمّم دون مسمار واحد.', 'قراءة المزيد', 'تفاعل بصري', NULL, '2026-04-17 13:50:58.778295+08', '2026-04-17 21:35:32.208995+08');
INSERT INTO "public"."city_feature_translations" ("id", "feature_id", "language", "title", "description", "btn_read_more", "btn_interactive", "btn_explore", "created_at", "updated_at") VALUES (28, 10, 'en', 'Architecture of Suzhou Garden', 'See the picture and discover the elegant architecture of Suzhou gardens — where walls, courtyards, moon gates, water, and wooden structures are carefully arranged to create harmony between nature and design.', 'Read More', 'Visual Interactive', NULL, '2026-04-17 13:57:01.138125+08', '2026-04-17 21:36:30.47352+08');
COMMIT;

