)
;
ALTER TABLE "public"."city_translations" OWNER TO "shenyefan";

-- ----------------------------
-- Records of city_translations
-- ----------------------------
BEGIN;
INSERT INTO "public"."city_translations" ("id", "city_id", "language", "name", "short_bio", "description", "created_at", "updated_at", "subtitle") VALUES (9, 3, 'ar', 'سوتشو', '"البندقية الشرقية" — مشهورة بحدائقها الكلاسيكية المدرجة على قائمة اليونسكو وشبكة قنواتها العريقة التي لا تزال تنبض بالحياة.', 'سوتشو، التي يُطلق عليها كثيراً "البندقية الشرقية"، مدينة بالغة الرقي تقع في دلتا نهر اليانغتسي. اشتُهرت عالمياً بحدائقها الكلاسيكية المصممة بعناية فائقة، إذ تُدرج أربعٌ منها ضمن مواقع التراث العالمي لليونسكو، وتمثل ذروة فن التصميم البستاني الصيني التقليدي. تمتد شبكة القنوات القديمة في المدينة، التي يعود تاريخها إلى 2500 عام، عبر أحياء الجدران البيضاء والأسقف القرميدية الداكنة، مانحةً الزوارَ لمحةً من الحياة إبان أسرتَي سونغ ومينغ. تتميز سوتشو أيضاً بكونها مسقط رأس أوبرا كونكيو، إحدى أقدم تقاليد المسرح الغنائي في العالم، وبمكانتها مركزاً رائداً لإنتاج الحرير الرفيع.', '2026-04-17 13:25:33.67689+08', '2026-04-17 20:19:51.031485+08', 'Historic Water Town');
INSERT INTO "public"."city_translations" ("id", "city_id", "language", "name", "short_bio", "description", "created_at", "updated_at", "subtitle") VALUES (2, 1, 'zh', '北京', '中国的帝都心脏——拥有世界上最大的宫殿建筑群，六百余年的王朝历史在此凝聚。', '北京是中华人民共和国的首都，也是全球最具历史底蕴的城市之一。这座城市建城已逾三千年，数百年间一直是中国的帝王之都，将古典辉煌与现代活力融为一体。北京拥有举世闻名的故宫——世界上现存规模最大、保存最完整的宫殿建筑群——以及天坛、颐和园和雄壮的长城。蜿蜒的胡同、古朴的四合院与气势磅礴的天安门广场，共同讲述着北京作为中华文明政治、文化与历史中心的千年故事。', '2026-04-17 13:25:32.695062+08', '2026-04-17 21:10:55.323908+08', 'Capital of China');
INSERT INTO "public"."city_translations" ("id", "city_id", "language", "name", "short_bio", "description", "created_at", "updated_at", "subtitle") VALUES (3, 1, 'ar', 'بكين', 'قلب الإمبراطورية الصينية — موطن أكبر مجمع قصور في العالم وأكثر من 600 عام من التاريخ الأسري.', 'بكين، عاصمة الصين، هي إحدى أعرق المدن في العالم. تأسست منذ أكثر من ثلاثة آلاف عام، وظلت عاصمةً إمبراطورية للصين لقرون متعاقبة، إذ تجمع بين الجلال العريق والحيوية المعاصرة. تضم المدينة المدينةَ المحرمة الشهيرة — أكبر مجمع قصور محفوظ على وجه الأرض — إلى جانب معبد السماء والقصر الصيفي وأجزاء شاسعة من سور الصين العظيم. تُجسّد الأزقة العتيقة (الهوتونغ) والمساكن الفناءية التقليدية (السيهيوان) وميدان تيانانمن الرحيب مكانةَ بكين بوصفها المركزَ الثقافي والسياسي والتاريخي للحضارة الصينية.', '2026-04-17 13:25:32.814407+08', '2026-04-17 21:10:55.365132+08', 'Capital of China');
INSERT INTO "public"."city_translations" ("id", "city_id", "language", "name", "short_bio", "description", "created_at", "updated_at", "subtitle") VALUES (4, 2, 'en', 'Xi''an', 'Ancient capital of 13 dynasties — birthplace of the Terracotta Army and guardian of China''s best-preserved city wall.', 'Xi''an is one of the oldest cities in China and served as the capital of no fewer than thirteen dynasties, making it a cradle of Chinese civilisation. Known internationally as the home of the extraordinary Terracotta Army — the 8,000-strong funerary force buried with the First Emperor Qin Shi Huang — the city also boasts the most intact ancient city wall in China, dating back to the Ming dynasty. The towering Big Wild Goose Pagoda reflects the city''s significance as a Buddhist centre, while the Great Mosque in the Muslim Quarter stands as a testament to Xi''an''s role as the eastern terminus of the Silk Road, where East met West for millennia.', '2026-04-17 13:25:32.93983+08', '2026-04-17 20:17:55.527985+08', 'Ancient Capital');
INSERT INTO "public"."city_translations" ("id", "city_id", "language", "name", "short_bio", "description", "created_at", "updated_at", "subtitle") VALUES (5, 2, 'zh', '西安', '十三朝古都——兵马俑的故乡，中国保存最完好的古城墙守护者。', '西安是中国最古老的城市之一，先后有十三个王朝在此建都，是中华文明的重要发祥地。这里因举世瞩目的兵马俑而享誉全球——那支由八千余件陶俑组成的地下军队，静静守护着秦始皇的陵寝。西安同时拥有中国保存最完整的古城墙（明代所建），巍峨的大雁塔是其佛教文化兴盛的历史见证，而回民街上的大清真寺，则诉说着西安作为丝绸之路东方起点、东西方文明汇聚之地的辉煌过往。', '2026-04-17 13:25:33.071572+08', '2026-04-17 20:17:55.582432+08', 'Ancient Capital');
INSERT INTO "public"."city_translations" ("id", "city_id", "language", "name", "short_bio", "description", "created_at", "updated_at", "subtitle") VALUES (6, 2, 'ar', 'شيان', 'عاصمة ثلاث عشرة أسرة حاكمة — موطن جيش التيراكوتا وحارسة أعرق أسوار المدن في الصين.', 'شيان هي إحدى أعرق المدن الصينية، وقد تعاقب على عاصمتها ثلاث عشرة أسرة حاكمة، مما جعلها مهداً للحضارة الصينية. تشتهر عالمياً بجيش التيراكوتا الأسطوري — ذلك الجيش الجنائزي المؤلف من أكثر من ثمانية آلاف تمثال طيني دُفن مع الإمبراطور الأول تشين شي هوانغ. كما تزهو المدينة بأكثر أسوارها القديمة اكتمالاً وصوناً في الصين، يعود تاريخه إلى عهد أسرة مينغ. تعكس برج البط البري الكبير المهيب مكانة شيان مركزاً بوذياً عريقاً، فيما يشهد المسجد الكبير في الحي الإسلامي على دور المدينة بوصفها الطرفَ الشرقي لطريق الحرير الذي ربط الشرق بالغرب عبر الألفيات.', '2026-04-17 13:25:33.19676+08', '2026-04-17 20:17:55.611325+08', 'Ancient Capital');
INSERT INTO "public"."city_translations" ("id", "city_id", "language", "name", "short_bio", "description", "created_at", "updated_at", "subtitle") VALUES (7, 3, 'en', 'Suzhou', 'The "Venice of the East" — celebrated for its UNESCO-listed classical gardens and an ancient canal network still alive today.', 'Suzhou, often called the "Venice of the East", is a city of extraordinary elegance set in the Yangtze River Delta. Renowned worldwide for its meticulously designed classical gardens — four of which are listed as UNESCO World Heritage Sites — Suzhou represents the pinnacle of traditional Chinese landscape art. The city''s ancient canal system, dating back 2,500 years, weaves through neighbourhoods of whitewashed walls and dark-tiled rooftops, offering a glimpse of life as it unfolded during the Song and Ming dynasties. Suzhou also holds a distinguished reputation as the birthplace of Kunqu opera, one of the world''s oldest musical theatre traditions, and as a major centre for the production of exquisite silk.', '2026-04-17 13:25:33.319639+08', '2026-04-17 20:19:50.975587+08', 'Historic Water Town');
INSERT INTO "public"."city_translations" ("id", "city_id", "language", "name", "short_bio", "description", "created_at", "updated_at", "subtitle") VALUES (8, 3, 'zh', '苏州', '"东方威尼斯"——以联合国世界遗产级别的古典园林和延续至今的千年运河网络闻名于世。', '苏州素有"东方威尼斯"之美誉，坐落于长江三角洲，以其精雕细琢的古典园林蜚声海内外——其中四座已被列入联合国教科文组织世界遗产名录，代表着中国传统园林艺术的最高境界。城内迄今仍在使用的古运河系统历经两千五百年风霜，穿越粉墙黛瓦的水乡街巷，再现了宋明两朝的水城风貌。苏州同时是昆曲的发源地——昆曲是世界上最古老的戏曲艺术之一，以及精美丝绸生产的重要中心，千百年来以丝绸之路传播中华文明之美。', '2026-04-17 13:25:33.439343+08', '2026-04-17 20:19:51.004159+08', 'Historic Water Town');
INSERT INTO "public"."city_translations" ("id", "city_id", "language", "name", "short_bio", "description", "created_at", "updated_at", "subtitle") VALUES (1, 1, 'en', 'Beijing', 'The imperial heart of China — home to the world''s largest palace complex and over 600 years of dynastic history.', 'Beijing, the capital of China, is one of the world''s most historic cities. Founded more than 3,000 years ago and serving as the imperial capital of China for centuries, Beijing blends ancient grandeur with modern dynamism. The city is home to the iconic Forbidden City — the largest preserved palace complex on earth — along with the Temple of Heaven, the Summer Palace, and vast stretches of the Great Wall. Its hutong alleyways, time-honoured courtyard residences (siheyuan), and the sweeping expanse of Tiananmen Square all speak to Beijing''s role as the cultural, political, and historical centre of the Chinese civilisation.', '2026-04-17 13:25:32.554652+08', '2026-04-17 21:10:55.293264+08', 'Capital of China');
COMMIT;

