BEGIN;
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (4, 2, 'zh', '第二章：其背后的传说', '["“螭吻（chw）”这一名称由两个字组成：“螭”（chw）——一种凶猛的猛禽，历史上常被认为是鸢或猫头鹰；以及“吻”（w）——意为“嘴唇”或“口”。二者结合，形象地描述了这种生物最显著的特征：张开的大口，紧紧咬住屋脊。在后来的朝代中，这种形象逐渐从鸟类演变得更像龙，有时也被称为“龙吻”（lóng w），或直接称为“正吻”（zhèng w），意为“正脊上的口形装饰”。"]', '2026-04-17 13:51:00.516787+08', '2026-04-17 23:23:48.047813+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (7, 3, 'en', 'Chapter III: The Legend Behind It', '["According to ancient Chinese legend, the chīwěn is the second son of the dragon king, a creature that lived in the sea and had the power to summon rain and control fire. Because fire was the greatest threat to timber-frame palace buildings, placing this water-commanding creature at the highest point of the roof was believed to protect the building from fire — the creature''s watery nature would suppress any flames that threatened the structure below."]', '2026-04-17 13:51:01.26323+08', '2026-04-17 23:26:13.015695+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (8, 1, 'ar', NULL, '[]', '2026-04-17 13:50:59.983114+08', '2026-04-17 21:20:01.544008+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (5, 1, 'zh', NULL, '[]', '2026-04-17 13:50:59.848077+08', '2026-04-17 21:20:01.497395+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (6, 4, 'en', 'Chapter III: The Colors of the Forbidden City — What Do They Mean?', '["Yellow — The Emperor''s Color (黄色 Huángsè): The sweeping roof tiles are glazed in imperial yellow, the most sacred color in Chinese culture. Yellow represented the earth, the centre of the universe, and the Son of Heaven himself. It was strictly forbidden for any ordinary citizen or official to use yellow on their home — doing so was punishable by death. Only the emperor''s buildings could wear this color.", "Red — Prosperity, Good Fortune, and Protection (红色 Hóngsè): The towering columns and walls are painted deep vermilion red. In Chinese culture red symbolises happiness, good luck, and the warding off of evil spirits. The lacquer used to achieve this colour also acted as a sealant, protecting the timber columns from moisture, rot, and insects for centuries."]', '2026-04-17 13:51:01.64818+08', '2026-04-17 20:39:38.774767+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (1, 3, 'zh', '第三章：其背后的传说', '["根据中国古代传说，螭吻是龙王的第二个儿子，是一种生活在海中的神兽，拥有呼风唤雨、控水御火的能力。由于火灾是木结构宫殿建筑最大的威胁，人们将这种能够掌控水的神兽安置在屋顶的最高处，以期起到防火的作用——其属水的特性被认为可以压制任何威胁建筑的火焰。"]', '2026-04-17 13:51:01.388026+08', '2026-04-17 23:26:13.041954+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (3, 2, 'en', 'Chapter II: The Legend Behind It', '["The name chw combines two characters: chw (ch) - a type of fierce bird of prey, historically identified as a kite or owl - and w (w) - meaning \"lips\" or \"mouth.\" Together the name describes the creature''s most defining characteristic: its open, devouring mouth biting down on the roof ridge. In later dynasties the creature evolved to look far more like a dragon than a bird, and was sometimes also called lóng w (lóng w) - \"dragon mouth\" - or simply zhèng w (zhèng w) - \"correct mouth ornament.\""]', '2026-04-17 13:51:00.383931+08', '2026-04-17 23:23:48.019492+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (2, 3, 'ar', 'العربية： الفصل الثالث: الأسطورة وراءه', '["وفقاً للأساطير الصينية القديمة، يُعدّ “تشي وِن” الابن الثاني لملك التنين، وهو مخلوق يعيش في البحر ويمتلك القدرة على استدعاء المطر والتحكم في النار. وبما أن الحرائق كانت أكبر تهديد للمباني الخشبية في القصور، فقد كان يُعتقد أن وضع هذا الكائن المسيطر على الماء في أعلى نقطة من السقف يوفر الحماية من الحريق، إذ إن طبيعته المائية قادرة على إخماد أي نيران قد تهدد البناء في الأسفل."]', '2026-04-17 13:51:01.51809+08', '2026-04-17 23:26:13.090996+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (11, 5, 'ar', NULL, '["الأخضر والأخضر المزرق — السماء والطبيعة (绿色/青色 Lǜsè/Qīngsè): انظر عن كثب إلى الأفاريز والأشرطة المطلية تحت خط السقف (彩画作 Cǎihuàzuò). تتزين بألوان أخضر-مزرق عميق مصنوعة من المالاكيت والأزوريت — معادن مطحونة إلى صباغ. مثّل الأخضر المزرق الخشبَ والنمو والربيع والسماء في نظام العناصر الخمسة الصيني (五行 Wǔxíng)، موازناً الأحمر والأصفر الدافئَين وواصلاً بين القصر الأرضي والعالم الطبيعي في الأعلى.", "الذهبي — السلطة الإلهية (金色 Jīnsè): طُبّق ورق الذهب الحقيقي على نقوش التنين ومقابض الأبواب والتفاصيل الزخرفية في جميع أنحاء القصر. ضاعف الذهبُ المكانةَ الإلهية للإمبراطور الذي كان يُعتقد أنه الممثل الأرضي للسماء. التنانين الذهبية المرسومة والمنقوشة لم تكن مجرد زينة — بل كانت رموزاً وقائية، وكان التنين ذو المخالب الخمسة محجوزاً حصرياً لاستخدام الإمبراطور."]', '2026-04-17 13:51:02.303728+08', '2026-04-17 20:39:54.388104+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (12, 6, 'en', 'Chapter I: The Dǒugǒng (斗拱) — China''s Most Ingenious Invention in Architecture', '["If there is one thing that makes Chinese imperial architecture unique in the entire world, it is the dǒugǒng. This interlocking bracket system, visible in the diagram above, is found on every major hall of the Forbidden City — and it was engineered without a single nail.", "What Is the Dǒugǒng? The word dǒugǒng is made of two parts: dǒu (斗) meaning ''block'' and gǒng (拱) meaning ''bow-shaped arm.'' Together they describe a cluster of wooden blocks and curved arms that stack and interlock at the top of a column to support the enormous weight of the roof above. Each cluster can contain dozens of individual pieces, all fitting together through pure joinery — no glue, no nails, no metal fasteners of any kind."]', '2026-04-17 13:51:02.564+08', '2026-04-17 20:42:04.476237+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (13, 6, 'zh', '第一章：斗拱——中国建筑中最精巧的发明', '["如果说有什么让中国皇家建筑在世界上独一无二，那就是斗拱。这种层层咬合的结构体系出现在故宫每一座主要殿宇上，且全程不用一颗钉子。", "斗拱是什么？\"斗拱\"由两部分组成：斗（dǒu），意为\"方形托块\"；拱（gǒng），意为\"弓形臂\"。合在一起，描述了一组木制托块与弯曲臂件层层叠摞、相互咬合、固定于柱头之上以承托屋顶巨大重量的系统。每组斗拱可包含数十个单独构件，全部依靠纯粹的榫卯工艺连接——无胶、无钉、无任何金属紧固件。"]', '2026-04-17 13:56:52.412895+08', '2026-04-17 20:42:04.505549+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (14, 6, 'ar', 'الفصل الأول: الدوجونغ (斗拱) — أروع اختراع في الهندسة المعمارية الصينية', '["إذا كان هناك شيء يجعل الهندسة المعمارية الإمبراطورية الصينية فريدة في العالم بأسره، فهو الدوجونغ. يظهر هذا النظام المتشابك من الدعامات الموضح في الرسم أعلاه في كل قاعة رئيسية من قاعات المدينة المحرمة — وقد صُمّم دون مسمار واحد.", "ما هو الدوجونغ؟ تتألف كلمة ''دوجونغ'' من جزأين: دو (斗) بمعنى ''كتلة'' وقونغ (拱) بمعنى ''ذراع قوسية الشكل''. ويصفان معاً مجموعة من الكتل الخشبية والأذرع المنحنية المتراكمة والمتشابكة عند قمة العمود لحمل الثقل الهائل للسقف. يمكن أن تحتوي كل مجموعة على عشرات القطع الفردية، جميعها تتلاءم معاً بالنجارة البحتة — بلا غراء ولا مسامير ولا أي أدوات تثبيت معدنية من أي نوع."]', '2026-04-17 13:56:52.540013+08', '2026-04-17 20:42:04.532648+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (9, 5, 'en', NULL, '["Green and Blue-Green — Heaven and Nature (绿色/青色 Lǜsè/Qīngsè): Look closely at the eaves and the painted bands beneath the roofline (彩画作 Cǎihuàzuò). These are decorated in deep blue-green tones made from malachite and azurite — minerals ground into pigment. Blue-green represented wood, growth, spring, and the heavens in the Chinese Five Elements system (五行 Wǔxíng). It balanced the warm red and yellow, connecting the earthly palace to the natural world above.", "Gold — Divine Authority (金色 Jīnsè): Real gold leaf was applied to dragon motifs, door knobs, and decorative details throughout the palace. Gold amplified the divine status of the emperor, who was believed to be the earthly representative of heaven. Dragons painted and carved in gold were not merely decorative — they were protective symbols, and the five-clawed dragon was reserved exclusively for the emperor''s use."]', '2026-04-17 13:51:02.0481+08', '2026-04-17 20:39:54.327999+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (10, 5, 'zh', NULL, '["绿色与青色——天与自然（绿色/青色 Lǜsè/Qīngsè）：仔细观察屋檐及檐下的彩画带（彩画作 Cǎihuàzuò），会发现那深邃的蓝绿色是用研磨成颜料的孔雀石和石青矿物制成的。在中国五行体系（五行 Wǔxíng）中，蓝绿色代表木、生长、春天和天空，平衡了暖红与黄色，将地上的宫殿与上方的自然天界相连。", "金色——神圣权威（金色 Jīnsè）：真金箔被贴敷在故宫各处的龙纹、门饰和装饰细节上。金色彰显了皇帝作为天之代言人在人间的神圣地位。金色龙纹不仅仅是装饰——它们是护佑的象征，五爪龙纹则是皇帝专属。"]', '2026-04-17 13:51:02.173235+08', '2026-04-17 20:39:54.357643+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (17, 8, 'en', NULL, '["盖斗板 (Gài dǒu bǎn) — Cover Board: A flat board sitting on top of the bracket cluster, providing a stable surface for the beams above to rest on.", "正心枋 (Zhèng xīn fāng) — Central Tie Beam: The central horizontal member running directly above the column line, forming the structural spine of the bracket layer.", "里拽枋 (Lǐ zhuāi fāng) — Inner Tie Beam: The inner counterpart to the outer tie beam, running along the interior side of the bracket cluster to balance forces from both sides.", "升 (Shēng) — Small Bearing Block: The small square blocks sitting between the curved arms, raising and supporting each layer as the cluster grows upward. The name literally means ''to rise.''", "昂 (Áng) — Diagonal Cantilever Arm: A long diagonal timber acting as a lever — one end projects outward under the eaves, while the other end is pinned down inside the building.", "翘 (Qiào) — Upward-Curved Arm: A short curved arm projecting at 90° to the main beam direction, building the bracket cluster outward in two directions simultaneously."]', '2026-04-17 13:56:53.243115+08', '2026-04-17 20:42:37.390035+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (18, 8, 'zh', NULL, '["盖斗板（Gài dǒu bǎn）——盖斗板：覆于整组斗拱顶部的平板，为其上承托的梁枋提供稳定的承受面。", "正心枋（Zhèng xīn fāng）——正心枋：沿柱列中线正上方延伸的中央水平枋件，构成整个斗拱层的结构主干。", "里拽枋（Lǐ zhuāi fāng）——里拽枋：外拽枋的内侧对应构件，沿斗拱内侧布置，平衡两侧拉力。", "升（Shēng）——升：置于弓形臂之间的小型方块，逐层垫高、支撑斗拱向上生长。其名\"升\"字，字面意为\"上升\"。", "昂（Áng）——昂：长条斜置木构件，起杠杆作用——一端向外挑出于屋檐之下，另一端压入建筑内部。", "翘（Qiào）——翘：与主梁方向成九十度角伸出的短弯臂，使斗拱同时向两个方向横向延伸。"]', '2026-04-17 13:56:53.379767+08', '2026-04-17 20:42:37.419364+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (15, 7, 'zh', '第二章：斗拱技术图解', '["飞椽（Fēi chuán）——飞椽：图示顶部斜置的木构件。它们是最外侧的椽子，形成屋角那优美的向上翘曲线条，向外伸出斗拱组以将檐角向上翘起。", "直椽（Zhí chuán）——直椽：位于飞椽之下，是沿屋面坡度直线铺设的主要结构椽子，将瓦片重量传递至下方的斗拱系统。", "挑檐枋（Tiāo yán fāng）——挑檐枋：从建筑向外挑出的水平构件，延伸屋顶的出檐深度。这道深远的出檐有效保护了下方朱红色木墙免受雨水侵蚀。", "外拽枋（Wài zhuāi fāng）——外拽枋：沿建筑长度方向连接各斗拱组的外侧水平枋，将荷载均匀分配到所有柱子上。"]', '2026-04-17 13:56:52.980047+08', '2026-04-17 20:42:18.022107+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (16, 7, 'ar', 'الفصل الثاني: المخطط التقني للدوجونغ', '["飞椽 (Fēi chuán) — الشناشيل الطائرة: القطع الخشبية المائلة في أعلى المخطط. هي الشناشيل الأبعد إلى الخارج التي تصنع الانحناء الدراماتيكي للأعلى عند زوايا السقف، وتمتد خارج مجموعة الدعامات لرفع طرف خط السقف إلى أعلى.", "直椽 (Zhí chuán) — الشناشيل المستقيمة: تقع تحت الشناشيل الطائرة، وهي الشناشيل الإنشائية الرئيسية التي تمتد مستقيمة على طول منحدر السقف، ناقلةً ثقل البلاط إلى نظام الدعامات في الأسفل.", "挑檐枋 (Tiāo yán fāng) — عارضة إسقاط الأفريز: عارضة أفقية تبرز إلى الخارج من المبنى لتمديد تدلي السقف. يحمي هذا التدلي الطويل الجدران الخشبية المطلية باللون الأحمر من المطر.", "外拽枋 (Wài zhuāi fāng) — العارضة الرابطة الخارجية: العارضة الأفقية الخارجية التي تربط مجموعات الدعامات على طول المبنى، موزعةً الحمل بالتساوي على جميع الأعمدة."]', '2026-04-17 13:56:53.113367+08', '2026-04-17 20:42:18.049164+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (19, 9, 'en', NULL, '["斗 (Dǒu) — Main Block: The square or rectangular blocks at every joint, receiving arms from below and supporting arms above. The bottom-most block sitting directly on the column capital is called the zuò dǒu (坐斗) or ''seat block.''", "额枋 (É fāng) — Architrave Beam: The large horizontal beam running between columns at the top of the wall, just below where the bracket cluster begins. It is the main beam connecting all columns together.", "拱 (Gǒng) — Bow Arm: The curved, bow-shaped horizontal arms extending outward from the column in all four directions. Under heavy loads they flex slightly, distributing stress rather than concentrating it."]', '2026-04-17 13:56:53.643147+08', '2026-04-17 20:42:56.954613+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (20, 9, 'ar', NULL, '["斗 (Dǒu) — الكتلة الرئيسية: الكتل المربعة أو المستطيلة عند كل وصلة، تستقبل الأذرع من الأسفل وتدعم الأذرع من الأعلى. الكتلة الأسفل الجالسة مباشرة فوق قمة العمود تُسمى zuò dǒu (坐斗) أو ''كتلة المقعد''.", "额枋 (É fāng) — عارضة الإطار: العارضة الأفقية الكبيرة الممتدة بين الأعمدة عند قمة الجدار، مباشرةً تحت بداية مجموعة الدعامات. إنها العارضة الرئيسية التي تربط جميع الأعمدة معاً.", "拱 (Gǒng) — الذراع القوسية: الأذرع الأفقية المنحنية على شكل قوس الممتدة للخارج من العمود في الاتجاهات الأربعة. تنحني قليلاً تحت الأحمال الثقيلة، موزعةً الإجهاد بدلاً من تركيزه."]', '2026-04-17 13:56:53.898042+08', '2026-04-17 20:42:57.016456+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (21, 19, 'zh', '第一章：建筑蓝图——解读城墙', '["清代工部原版工程图纸（《清工部工程做法则例》）呈现了城墙门楼的截面图与立面图。这类图纸——立面图（lìmiàn tú）和剖面图（pōumiàn tú）——是皇家建筑师与工匠数百年来建造和维护城墙的工作依据。", "解读蓝图：城墙外壁（外壁 wài bì）呈现出以顺砖法砌筑的青砖垂直外立面；截面则揭示了墙体真正的结构核心——夯土层（夯土 hāngtǔ），由下向上略有收分，赋予城墙特有的梯形截面轮廓。", "城墙底部（墙根）宽度为十五至十八米，顶部马道（mǎdào）约宽十二至十四米——足以并行五匹战马，确保军队和辎重车辆能够快速沿墙机动。"]', '2026-04-17 13:56:57.568101+08', '2026-04-17 20:47:25.268294+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (25, 22, 'en', 'Chapter I: The Art of Borrowed Scenery — 借景 (Jièjǐng)', '["The defining principle of Suzhou garden design is 借景 (jièjǐng) — ''borrowed scenery.'' Rather than building a garden that is self-contained, Suzhou garden designers deliberately framed views of the world beyond the garden walls — distant hills, the sky, neighbouring trees — incorporating them into the garden''s visual composition as if they were part of the design.", "Every window, doorway, corridor turn, and pavilion placement in a Suzhou garden was calculated to frame a view. The visitor is never meant to see the whole garden at once; instead, the experience unfolds as a sequence of carefully composed scenes, each one different from the last.", "This principle of sequential revelation — where the garden''s full extent is never visible from any single point — creates a sense of depth and scale that far exceeds the garden''s actual physical size. The Humble Administrator''s Garden covers just 5.2 hectares, yet it feels inexhaustible."]', '2026-04-17 13:57:02.484938+08', '2026-04-17 21:00:55.169447+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (26, 21, 'en', 'Chapter III: The Gate Tower — 城楼 (Chénglóu)', '["The gate tower is the most architecturally complex part of the entire wall system. Unlike the wall itself — essentially a massive earthwork — the gate tower is a full timber-frame building constructed in the finest tradition of Chinese imperial architecture.", "The Three-Tiered Roof System: The gate tower has three separate roof levels, each with its own set of sweeping eaves and glazed tile capping. This triple-roof form — called 三重檐 (sān chóng yán) — was reserved for buildings of the highest military and civic importance. Each roof level has its own bracket system (斗拱 dǒugǒng) supporting the eave overhang, creating the layered, rhythmic silhouette that defines the Xi''an skyline.", "The Sticky Rice Mortar Secret: The brick facing of the Xi''an city wall was laid using a revolutionary mortar invented during the Ming dynasty — a mixture of sticky glutinous rice (糯米 nuòmǐ) juice, slaked lime, and sand. This organic-mineral composite achieved a bonding strength far exceeding conventional lime mortar. After 650 years, sections of this wall remain so hard that modern drills struggle to penetrate them."]', '2026-04-17 13:56:59.537797+08', '2026-04-17 20:48:45.474195+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (27, 21, 'zh', '第三章：城楼——城墙建筑的精华', '["城楼是整个城墙系统中建筑结构最为复杂的部分。与城墙本体——本质上是一项庞大的土方工程——不同，城楼是一座以中国皇家建筑最高标准建造的完整木结构建筑。", "三重檐屋顶体系：城楼拥有三层独立屋顶，每层各设飞檐和琉璃瓦收边。这种三重檐屋顶形式（sān chóng yán）专属于军事和城市功能中最为重要的建筑。每层屋顶均配有独立的斗拱组承托出檐，形成了定义西安城市天际线的层叠、有节奏的轮廓线。", "糯米灰浆的秘密：西安城墙砖砌外表面使用了明代研发的革命性砂浆——以糯米汁（nuòmǐ）、消石灰和细沙按比例混合而成。这种有机-矿物复合材料的粘结强度远超普通石灰砂浆。历经六百五十年，城墙某些区段至今坚硬异常，现代钻头都难以轻易凿入。"]', '2026-04-17 13:56:59.755183+08', '2026-04-17 20:48:45.503776+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (23, 1, 'en', 'Chapter I: Chw (Chw) - The Dragon That Guards the Roof', '["The large dragon-like creatures you see gripping the two ends of every major roof ridge in Chinese imperial architecture are called chw (Chw) - one of the most important and visually dramatic elements in all of Chinese architectural tradition. On the Forbidden City''s Hall of Supreme Harmony alone, the two chw at either end of the main ridge stand over 3.4 metres tall and weigh more than 4 tonnes each - making them the largest roof ornaments ever created in Chinese history."]', '2026-04-17 13:50:59.707946+08', '2026-04-17 21:20:01.47152+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (31, 7, 'en', 'Chapter II: Technical Diagram of the Dǒugǒng', '["飞椽 (Fēi chuán) — Flying Rafters: The angled timber pieces at the top of the diagram. These are the outermost rafters that create the dramatic upward curve at the corners of the roof. They extend beyond the bracket cluster to push the roofline tip upward.", "直椽 (Zhí chuán) — Straight Rafters: Sitting beneath the flying rafters, these are the main structural rafters that run straight along the roof slope, carrying the weight of the tiles down to the bracket system below.", "挑檐枋 (Tiāo yán fāng) — Eave-Projecting Beam: A horizontal beam that projects outward from the building, extending the roof''s overhang. This long overhang protected the red-painted timber walls from rain.", "外拽枋 (Wài zhuāi fāng) — Outer Tie Beam: The outer horizontal beam connecting bracket clusters along the building, distributing the load evenly across all columns."]', '2026-04-17 13:56:52.682892+08', '2026-04-17 20:42:17.981992+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (33, 9, 'zh', NULL, '["斗（Dǒu）——斗：位于每个节点上的方形或长方形托块，下承弓形臂，上托弓形臂。最底层直接坐于柱头之上的那块斗称为\"坐斗\"。", "额枋（É fāng）——额枋：在墙顶、斗拱起点之下，横贯各柱之间的大型水平构件，是连接所有立柱的主梁。", "拱（Gǒng）——拱：从柱子向四个方向伸出的弯曲弓形水平臂。在重载作用下，拱臂会略微弯曲，将应力分散传递而非集中于一点。"]', '2026-04-17 13:56:53.772783+08', '2026-04-17 20:42:56.984705+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (34, 19, 'en', 'Chapter I: The Architectural Blueprint — Reading the Wall', '["The original Qing Dynasty engineering drawing (清工部工程做法则例) shows a cross-section and elevation diagram of the city wall gate tower. This type of drawing — 立面图 (lìmiàn tú, elevation drawing) and 剖面图 (pōumiàn tú, cross-section drawing) — was the working document used by imperial architects to build and maintain the wall across centuries.", "Reading the blueprint: the outer face of the wall (外壁 wài bì) shows a sheer vertical surface of fired grey brick, laid in a running bond pattern. Behind it, the cross-section reveals the rammed earth core (夯土 hāngtǔ) — the wall''s true structural heart — which tapers slightly from base to top, giving the wall its characteristic trapezoidal profile.", "The base of the wall (wall foot) is 15–18 metres wide, while the top walkway (马道 mǎdào, horse road) is approximately 12–14 metres across — wide enough for five cavalry horses to ride abreast, allowing troops and supply carts to move rapidly along the wall''s length."]', '2026-04-17 13:56:56.789822+08', '2026-04-17 20:47:25.226342+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (29, 4, 'zh', '第三章：故宫的色彩——颜色背后的含义', '["黄色——皇帝之色（黄色 Huángsè）：宽阔的屋面覆以帝王专用的黄色琉璃瓦，这是中国文化中最神圣的颜色。黄色象征大地、宇宙的中心以及天子本身。任何普通百姓或官员在自家房屋上使用黄色，均属死罪。只有皇帝的建筑才能拥有这种颜色。", "红色——繁荣、吉祥与辟邪（红色 Hóngsè）：高大的柱子和宫墙涂以深朱砂红色。在中国文化中，红色象征喜庆、好运和驱邪辟鬼。涂抹这种颜色所用的生漆同时起到密封作用，数百年来有效保护木柱免受潮气、腐朽和虫蛀侵害。"]', '2026-04-17 13:51:01.778018+08', '2026-04-17 20:39:38.806025+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (32, 8, 'ar', NULL, '["盖斗板 (Gài dǒu bǎn) — لوح الغطاء: لوح مسطح يجلس فوق مجموعة الدعامات، يوفر سطحاً ثابتاً لارتكاز العوارض فوقه.", "正心枋 (Zhèng xīn fāng) — العارضة الرابطة المركزية: العضو الأفقي المركزي الممتد مباشرة فوق خط الأعمدة، يشكّل العمود الفقري الإنشائي لطبقة الدعامات.", "里拽枋 (Lǐ zhuāi fāng) — العارضة الرابطة الداخلية: نظيرة العارضة الخارجية من الداخل، تمتد على الجانب الداخلي من مجموعة الدعامات لموازنة القوى من كلا الجانبين.", "升 (Shēng) — الكتلة الحاملة الصغيرة: الكتل المربعة الصغيرة الجالسة بين الأذرع المنحنية، ترفع كل طبقة وتدعمها كلما نمت المجموعة لأعلى. ويعني الاسم حرفياً ''الارتفاع''.", "昂 (Áng) — الذراع القنطري القطري: خشبة قطرية طويلة تعمل كرافعة — طرف منها يبرز للخارج تحت الأفريز، بينما الطرف الآخر مثبت في داخل المبنى.", "翘 (Qiào) — الذراع المنحنية للأعلى: ذراع منحنية قصيرة تبرز بزاوية 90 درجة بالنسبة لاتجاه العارضة الرئيسية، ناشرةً مجموعة الدعامات في اتجاهين في آن واحد."]', '2026-04-17 13:56:53.51311+08', '2026-04-17 20:42:37.448254+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (38, 20, 'ar', 'الفصل الثاني: قلب التربة المدكوكة — 夯土 (Hāngtǔ)', '["تكمن عبقرية سور مدينة شيان ليس في واجهته الآجرية بل فيما لا يمكن رؤيته: قلب التربة المدكوكة الهائل الذي يمنح السور صلابته الاستثنائية. كانت عملية الـ夯土 السداسية من أعرق تقنيات الهندسة الصينية وأكثرها رقياً.", "① الملء (填 Tián) — تُسكب تربة رخوة ممزوجة بالجير ومواد لاصقة عضوية في ألواح قوالب خشبية، تُتحكم في كل طبقة بدقة بسماكة 120–150 ملم قبل الدك.", "② التسوية (平 Píng) — تُسوّى التربة المضافة حديثاً بالأيدي أو أدوات صغيرة لضمان كثافة موحدة عبر العرض الكامل.", "③ الدهس (踏 Tà) — قبل الدك، يمشي العمال عبر طبقة التربة الرخوة بنمط منهجي، محققين ضغطاً أولياً بأقدامهم.", "④ الدك (夯 Hāng) — تُضرب طبقة التربة باستمرار وبالتساوي بأدوات دك خشبية أو حجرية ثقيلة. هذه هي المرحلة الحاسمة التي تحول الحشو الرخو إلى كتلة إنشائية حاملة للأحمال وكثيفة.", "النتيجة: قلب السور بمقاومة ضغط مماثلة للخرسانة الحديثة — وقد صمد 650 عاماً."]', '2026-04-17 13:56:59.165682+08', '2026-04-17 20:48:48.184012+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (22, 20, 'zh', '第二章：夯土核心——夯土工艺', '["西安城墙真正的精妙之处，不在于可见的砖石外表，而在于那看不见的巨大夯土核心——正是它赋予了城墙卓越的体量与坚韧。六步夯土法是中国最古老、最成熟的工程技艺之一。", "①填（Tián）——将拌有石灰和有机粘合剂的松散土壤铲入木制模板，每层在压实前严格控制厚度为一百二十至一百五十毫米。", "②平（Píng）——用手或小型工具将新填土层抹平，确保全宽范围内密实度均匀。", "③踏（Tà）——夯打开始前，工人按规律步伐踩踏松散土层，以脚力完成初步压实。", "④夯（Hāng）——操持重型木夯或石夯，持续均匀地撞击土层。这是将松散填土转化为密实承重结构体的关键工序。", "⑤补（Bǔ）——对模板边角区域重点补夯，确保整个截面全部均匀压实。", "最终成果：墙体核心的抗压强度堪比现代混凝土——且已屹立了六百五十年。"]', '2026-04-17 13:56:58.476268+08', '2026-04-17 20:48:48.153728+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (39, 23, 'en', 'Chapter I: Chw (Chw) - The Dragon That Guards the Roof', '["The large dragon-like creatures you see gripping the two ends of every major roof ridge in Chinese imperial architecture are called chw (Chw) - one of the most important and visually dramatic elements in all of Chinese architectural tradition. On the Forbidden City''s Hall of Supreme Harmony alone, the two chw at either end of the main ridge stand over 3.4 metres tall and weigh more than 4 tonnes each - making them the largest roof ornaments ever created in Chinese history."]', '2026-04-17 21:22:10.849821+08', '2026-04-17 21:41:01.244121+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (36, 23, 'ar', 'العربية', '["الفصل الأول: تشي وِن (Chw) — التنين الحارس لسطح السقف\nتُسمّى الكائنات الضخمة الشبيهة بالتنين التي تراها تمسك بطرفي حافة السقف في العمارة الإمبراطورية الصينية بـ”تشي وِن” (Chw)، وهي من أهم وأكثر العناصر الزخرفية إثارةً في التقاليد المعمارية الصينية. في قاعة الانسجام الأسمى داخل المدينة المحرمة وحدها، يصل ارتفاع كل تمثال من هذين التشي وِن إلى أكثر من 3.4 أمتار، ويزن كل واحد منهما أكثر من 4 أطنان، مما يجعلهما أكبر زينة سقفية صُنعت في تاريخ الصين."]', '2026-04-17 21:22:10.920634+08', '2026-04-17 21:41:01.312705+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (40, 23, 'zh', '第一章：螭吻（Chw）——守护屋脊的龙', '["在中国皇家建筑中，你所看到的那些紧紧咬住屋脊两端的大型龙形构件，被称为螭吻（Chw）。它是中国建筑传统中最重要、最具视觉冲击力的装饰元素之一。仅以紫禁城的太和殿为例，其正脊两端的螭吻高达3.4米以上，每个重量超过4吨，堪称中国历史上体量最大的屋顶装饰。"]', '2026-04-17 21:22:10.892611+08', '2026-04-17 21:41:01.28362+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (24, 21, 'ar', 'الفصل الثالث: برج البوابة — 城楼 (Chénglóu)', '["برج البوابة هو الجزء الأكثر تعقيداً من الناحية المعمارية في نظام السور بأكمله. وعلى خلاف السور ذاته — الذي هو جوهرياً عمل ترابي ضخم — فإن برج البوابة مبنى هيكلي خشبي كامل شُيّد بأرفع تقاليد الهندسة المعمارية الإمبراطورية الصينية.", "نظام السقف ثلاثي المستويات: لبرج البوابة ثلاثة مستويات سقف منفصلة، لكل منها مجموعته من الأفاريز المنحنية وتغطية البلاط الخزفي. هذا الشكل ثلاثي السقف — المسمى 三重檐 (sān chóng yán) — كان محجوزاً للمباني ذات الأهمية العسكرية والمدنية القصوى. لكل مستوى سقف نظام دعامات (斗拱 dǒugǒng) خاص به يدعم إسقاط الأفريز، مُشكّلاً الصورة الهندسية الطبقية الإيقاعية التي تُميّز أفق شيان.", "سر الملاط من الأرز اللزج: رُصّت الطبقة الآجرية الخارجية لسور شيان بملاط ثوري اخترعته أسرة مينغ — خليط من عصير الأرز الغليظ اللزج (糯米 nuòmǐ) والجير المطفأ والرمل. حقّق هذا المركب العضوي-المعدني قوة ترابط تفوق بكثير ملاط الجير التقليدي. بعد 650 عاماً، لا تزال أقسام من هذا السور صلبة جداً لدرجة أن المثاقب الحديثة تعجز عن اختراقها."]', '2026-04-17 13:57:00.706723+08', '2026-04-17 20:48:45.544354+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (37, 20, 'en', 'Chapter II: The Rammed Earth Core — 夯土 (Hāngtǔ)', '["The genius of the Xi''an city wall lies not in its brick facing but in what you cannot see: the massive rammed earth core that gives the wall its extraordinary bulk and resilience. The six-step process of 夯土 construction was one of China''s oldest and most refined engineering techniques.", "① Fill (填 Tián) — Loose earth mixed with lime and organic binders is poured into wooden formwork panels, each layer carefully controlled to 120–150 mm in depth before compaction.", "② Level (平 Píng) — The newly added earth is smoothed flat using hands or small tools to ensure uniform density across the full width.", "③ Tread (踏 Tà) — Before ramming, workers walk across the loose earth layer in a systematic pattern, applying initial compaction by foot.", "④ Ram (夯 Hāng) — Heavy wooden or stone ramming tools are driven into the earth layer continuously and evenly. This is the critical stage that transforms loose fill into a dense, load-bearing structural mass.", "⑤ Supplement (补 Bǔ) — Special attention is given to edges and corners to ensure uniform compaction throughout the full cross-section.", "The result: a wall core with a compressive strength comparable to modern concrete — and one that has stood for 650 years."]', '2026-04-17 13:56:58.078251+08', '2026-04-17 20:48:48.110172+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (30, 4, 'ar', 'الفصل الثالث: ألوان المدينة المحرمة — ماذا تعني؟', '["الأصفر — لون الإمبراطور (黄色 Huángsè): بلاط السقف المنحني مطلي بالأصفر الإمبراطوري، أقدس الألوان في الثقافة الصينية. مثّل الأصفر الأرضَ ومركز الكون وابن السماء نفسه. كان يُحظر تماماً على أي مواطن عادي أو مسؤول استخدام اللون الأصفر في منزله — وكانت عقوبة ذلك الإعدام. المباني الإمبراطورية وحدها يحق لها ارتداء هذا اللون.", "الأحمر — الازدهار والحظ الحسن والحماية (红色 Hóngsè): طُليت الأعمدة والجدران الشاهقة باللون الأحمر القرمزي العميق. يرمز اللون الأحمر في الثقافة الصينية إلى السعادة والحظ السعيد وطرد الأرواح الشريرة. كما أن اللك المستخدم لتحقيق هذا اللون أدّى وظيفة العازل أيضاً، محمياً الأعمدة الخشبية من الرطوبة والتعفن والحشرات لقرون."]', '2026-04-17 13:51:01.918359+08', '2026-04-17 20:39:38.83489+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (35, 19, 'ar', 'الفصل الأول: المخطط المعماري — قراءة السور', '["يُظهر الرسم الهندسي الأصلي من عهد أسرة تشينغ (清工部工程做法则例) مقطعاً وارتفاعاً لبرج بوابة السور. هذا النوع من الرسوم — 立面图 (lìmiàn tú، رسم الارتفاع) و 剖面图 (pōumiàn tú، رسم المقطع) — كان وثيقة العمل التي استخدمها المهندسون المعماريون الإمبراطوريون لبناء السور والحفاظ عليه عبر القرون.", "قراءة المخطط: يُظهر الوجه الخارجي للسور (外壁 wài bì) سطحاً عمودياً من الطوب الرمادي المحروق المرصوف بنمط متدرج. خلفه، يكشف المقطع العرضي عن قلب التربة المدكوكة (夯土 hāngtǔ) — القلب الإنشائي الحقيقي للسور — الذي يضيق قليلاً من القاعدة إلى الأعلى، مانحاً السور مقطعه شبه منحرف المميز.", "قاعدة السور تبلغ 15–18 متراً في العرض، بينما الممشى العلوي (马道 mǎdào، طريق الخيل) يبلغ نحو 12–14 متراً — بعرض يكفي لخمسة خيول فرسان جنباً إلى جنب، مما يتيح للقوات وعربات الإمداد التحرك بسرعة على طول السور."]', '2026-04-17 13:56:57.78475+08', '2026-04-17 20:47:25.296316+08');
INSERT INTO "public"."feature_chapter_translations" ("id", "chapter_id", "language", "title", "paragraphs", "created_at", "updated_at") VALUES (28, 2, 'ar', 'العربية： الفصل الثاني: الأسطورة وراءه', '["يتكوّن اسم “تشي وِن” (chw) من مقطعين: “تشي” (chw) — وهو طائر جارح شرس، كان يُعتقد تاريخياً أنه نوع من الحدأة أو البومة — و”وِن” (w) — وتعني “الشفاه” أو “الفم”. معاً، يصف الاسم أبرز سمة لهذا الكائن: فمه المفتوح الذي يلتهم ويعضّ حافة السقف. ومع مرور الزمن، خصوصاً في السلالات اللاحقة، تطور شكل هذا الكائن ليصبح أقرب إلى التنين منه إلى الطائر، وأُطلق عليه أحياناً اسم “فم التنين” (lóng w) أو ببساطة “زينة الفم الصحيحة” (zhèng w)."]', '2026-04-17 13:51:01.128879+08', '2026-04-17 23:23:48.091298+08');
COMMIT;

