-- ----------------------------
-- Table structure for landmark_translations
-- ----------------------------
DROP TABLE IF EXISTS "public"."landmark_translations";
CREATE TABLE "public"."landmark_translations" (
  "id" int4 NOT NULL DEFAULT nextval('landmark_translations_id_seq'::regclass),
  "landmark_id" int4 NOT NULL,
  "language" varchar(5) COLLATE "pg_catalog"."default" NOT NULL,
  "name" varchar(200) COLLATE "pg_catalog"."default" NOT NULL,
  "short_description" varchar(400) COLLATE "pg_catalog"."default",
  "description" text COLLATE "pg_catalog"."default",
  "historical_background" text COLLATE "pg_catalog"."default",
  "visiting_tips" varchar(600) COLLATE "pg_catalog"."default",
  "created_at" timestamptz(6) NOT NULL DEFAULT now(),
  "updated_at" timestamptz(6) NOT NULL DEFAULT now()
)
;
ALTER TABLE "public"."landmark_translations" OWNER TO "shenyefan";

-- ----------------------------
-- Records of landmark_translations
-- ----------------------------
BEGIN;
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (5, 2, 'zh', '天坛', '气势恢宏的皇家祭祀建筑群，历代皇帝在此祈谷祈年，被列为联合国世界遗产。', '天坛坐落于北京南部，是明代宗教建筑的杰出代表，四周环绕着宽阔幽静的园林。祈年殿以其三重蓝色琉璃瓦攒尖顶著称，是中国最具辨识度的建筑标志之一。建筑群还包括圜丘坛与皇穹宇，三者由高架的丹陛桥相连。', '天坛始建于明永乐四年至十八年（1406—1420年），嘉靖九年（1530年）进行了大规模扩建。每年两次，皇帝以"天子"之身在此举行祭天大典，祈求风调雨顺、五谷丰登。1998年，天坛被联合国教科文组织列入世界遗产名录。', '天坛公园是北京市民晨练和休闲的热门场所，尤以清晨最为热闹。工作日参观可享受更安静的游览体验。从南侧眺望祈年殿视角最佳。', '2026-04-17 13:25:40.554736+08', '2026-04-17 23:07:27.169409+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (2, 1, 'zh', '故宫', '世界上规模最大、保存最完整的皇家宫殿，明清两朝共二十四位皇帝曾在此居住。', '故宫，又称"紫禁城"，坐落于北京中轴线的核心位置。占地约七十二万平方米，现存建筑九百八十座，是近五个世纪以来中国政治权力与礼仪文化的中心。金黄色的琉璃瓦、朱红色的宫墙与巍峨的城门楼，共同构成了令人叹为观止的皇权建筑语言。', '故宫始建于明永乐四年（1406年），历时十四年建成，动用工匠和劳役逾百万之众。1987年被列入联合国教科文组织世界遗产名录，如今以故宫博物院的身份向公众开放，是中国参观人数最多的文化机构之一。', '建议清晨入场以避开人流高峰。故宫每周一闭馆。参观时间建议留足三至四小时。正门处提供多语言语音导览。', '2026-04-17 13:25:40.049382+08', '2026-04-17 23:06:31.135641+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (4, 2, 'en', 'Temple of Heaven', 'A magnificent imperial sacrificial complex where emperors prayed for good harvests — a UNESCO World Heritage Site.', 'The Temple of Heaven is a masterpiece of Ming-dynasty religious architecture set within a vast, serene parkland in southern Beijing. The iconic Hall of Prayer for Good Harvests, with its triple-tiered blue-tiled roof, is among the most recognisable symbols of China. The complex also includes the Circular Mound Altar and the Imperial Vault of Heaven, all connected by the elevated Danbi Bridge.', 'Built between 1406 and 1420, the complex was expanded under the Jiajing Emperor in 1530. It served as the venue for the imperial Heaven Worship ceremony, held twice annually, in which the emperor — as the Son of Heaven — appealed to the heavens for bountiful crops. It was inscribed as a UNESCO World Heritage Site in 1998.', 'The park surrounding the temple is a beloved gathering spot for locals, especially in the morning. Visit on weekdays for a quieter experience. The best views of the Hall of Prayer are from the south.', '2026-04-17 13:25:40.424918+08', '2026-04-17 23:07:27.13268+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (12, 4, 'ar', 'ميدان تيانانمن', 'القلب الرمزي الشاسع للصين الحديثة — أحد أكبر الميادين العامة في العالم، يتناثر حوله شواهد تاريخية بارزة.', 'ميدان تيانانمن ساحة حضرية هائلة تمتد على 440,000 متر مربع في وسط بكين، مما يجعلها من أكبر الميادين العامة على وجه الأرض. يحدّها من الشمال بوابة السلام السماوي (التي أعلن منها ماو تسي تونغ قيام جمهورية الصين الشعبية عام 1949م)، ومن الغرب قاعة الشعب الكبرى، ومن الشرق المتحف الوطني الصيني. يتوسط الميدانَ نصبُ أبطال الشعب التذكاري ومقبرة الرئيس ماو.', 'يؤدي الموقع وظيفته مكاناً للتجمعات الاحتفالية منذ عهد أسرة مينغ. وسّع الميدانَ بشكله الراهن توسعةً جوهرية بين عامَي 1958م و1959م لاستيعاب الاجتماعات السياسية الحاشدة. تستقطب مراسم رفع العلم عند الفجر التي يؤديها جيش التحرير الشعبي آلاف الزوار يومياً.', 'مراسم رفع العلم عند الشروق تجربة لا تُنسى — احرص على الوصول قبل نصف ساعة على الأقل. يستلزم دخول الميدان المرور بنقاط تفتيش أمنية. التصوير مسموح به في جميع أرجاء الميدان.', '2026-04-17 13:25:42.189681+08', '2026-04-17 20:11:14.215009+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (8, 3, 'zh', '颐和园', '中国规模最大、保存最完整的皇家园林，以昆明湖与万寿山为核心。', '颐和园是中国现存最大、保存最完好的皇家园林，总面积约二点九平方公里。核心景区昆明湖约占全园面积的四分之三，万寿山从北岸拔地而起，山顶的佛香阁金碧辉煌。长廊、亭台楼阁和汉白玉石桥相互映衬，将人工与自然之美融为一体。', '颐和园始建于清乾隆十五年（1750年），最初由乾隆皇帝为其母亲六十寿辰所建。1860年遭英法联军大规模破坏，后由慈禧太后于1886年挪用海军军费重建。1998年被联合国教科文组织列入世界遗产名录。', '乘船游览昆明湖可从湖面观赏万寿山的绝美全景。全长七百二十八米的长廊是全园最亮眼的看点。春季赏樱、冬季观湖面冰景，各有不同风韵。', '2026-04-17 13:25:41.69663+08', '2026-04-17 20:10:08.565274+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (10, 4, 'en', 'Tiananmen Square', 'The vast symbolic heart of modern China — one of the world''s largest public squares, flanked by historic monuments.', 'Tiananmen Square is a colossal urban plaza spanning 440,000 square metres in central Beijing, making it one of the largest public squares on earth. It is flanked by the Gate of Heavenly Peace to the north (where Mao Zedong proclaimed the People''s Republic in 1949), the Great Hall of the People to the west, and the National Museum of China to the east. At its centre stands the Monument to the People''s Heroes and the Mausoleum of Chairman Mao.', 'The site has served as a ceremonial gathering ground since the Ming dynasty. The square in its current form was substantially expanded in 1958–59 to accommodate mass political gatherings. The flag-raising ceremony at dawn, performed by the People''s Liberation Army, draws thousands of visitors daily.', 'The flag-raising ceremony at sunrise is a memorable experience — arrive at least 30 minutes early. Security checks are required to enter the square. Photography is permitted throughout.', '2026-04-17 13:25:41.944639+08', '2026-04-17 20:11:14.144286+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (11, 4, 'zh', '天安门广场', '现代中国的精神象征与政治中心——世界上面积最大的城市广场之一，四周分布着重要历史建筑。', '天安门广场位于北京中轴线核心，占地约四十四万平方米，是世界上规模最大的城市广场之一。广场北侧为天安门城楼（1949年毛泽东在此宣告中华人民共和国成立），西侧为人民大会堂，东侧为中国国家博物馆，中央矗立着人民英雄纪念碑和毛主席纪念堂。', '这片区域自明代起便作为礼仪集会场所使用。现有规模的广场于1958—1959年经大规模扩建，以容纳大型政治活动。中国人民解放军每日在日出时举行的升旗仪式，每天吸引数千名游客前来观礼。', '日出时分的升旗仪式是难忘的历史体验，建议提前至少三十分钟到达。进入广场需通过安检。全程均可拍照留念。', '2026-04-17 13:25:42.064493+08', '2026-04-17 20:11:14.188853+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (14, 5, 'zh', '长城·八达岭', '游客最多的长城精华段，登高远眺可览北京北郊山岭间的壮阔风光。', '八达岭长城是长城最著名、修缮最完整的段落，位于北京市区以北约七十公里。城墙沿险峻山脊蜿蜒而行，此段墙体高约七点八米，顶宽约六米。烽火台每隔一百至两百米设置一座，昔日均有戍卒驻守，负责传递军情与防御。', '长城历经多个朝代修建，八达岭段属明代（1368—1644年）所筑。长城原本绵延中国北方逾两万一千公里，是抵御北方游牧民族入侵的主要军事屏障。1957年，八达岭成为第一个向外国贵宾和游客开放的长城段落。', '建议提前在网上购票。周末和节假日人流极多。北8楼段坡度更陡，风景更壮阔，且人相对较少。请穿舒适的运动鞋。', '2026-04-17 13:25:43.149413+08', '2026-04-17 20:11:56.869754+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (16, 6, 'en', 'Xi''an City Wall', 'The most complete ancient city wall in China — a 13.74 km Ming-dynasty fortification still encircling the old city.', 'The Xi''an City Wall is a remarkable feat of military architecture from the Ming dynasty (1370 AD), forming a nearly perfect rectangle around the old city centre. Standing 12 metres high, 15–18 metres wide at the base, and stretching 13.74 kilometres in total circumference, it is the most intact ancient city wall in China. The wall features 98 battlements, 4 main gates, 4 watchtowers, and a defensive moat. Today, visitors can walk or cycle the entire perimeter along the broad, flat top.', 'The present wall was built on the foundations of the Tang-dynasty imperial city wall, which itself dates to 618 AD. Construction of the Ming wall was completed in 1370 under the Hongwu Emperor. The wall was built using a revolutionary technique: a mortar of sticky rice mixed with lime, which has proven extraordinarily durable — sections remain intact after 650 years.', 'Renting a bicycle to ride the full circuit (13.74 km, roughly 1.5–2 hours) is highly recommended. The wall is illuminated beautifully at night. The South Gate (Yongning Gate) is the main entrance and the grandest.', '2026-04-17 13:25:43.39452+08', '2026-04-17 20:27:56.751288+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (17, 6, 'zh', '西安城墙', '中国保存最完整的古代城墙——一圈总长13.74公里的明代军事要塞，至今仍完整环绕古城核心。', '西安城墙是中国现存规模最大、保存最完整的古代城垣，始建于明洪武三年（1370年），近似完美的矩形环绕古城中心。城墙高约十二米，底部宽十五至十八米，周长约十三点七四公里。全线共设垛口九十八处、城门四座、角楼四座，并配有护城河。游客如今可沿宽阔平坦的城墙顶部步行或骑行，将古城风貌尽收眼底。', '现存城墙是在唐代皇城夯土墙基础上扩建而成，其历史可追溯至唐高祖武德年间（618年）。明代城墙于洪武三年在明太祖朱元璋的主持下建成。城墙采用了一种革命性的建造技艺：以糯米汁与石灰混合制成的"糯米灰浆"作为胶凝材料，历经六百五十年依然坚固如初。', '强烈推荐租骑自行车完整游览全程（约十三点七四公里，骑行一点五至两小时）。入夜后城墙灯光璀璨，别有韵味。南门（永宁门）是主入口，也是规制最为宏大的城门。', '2026-04-17 13:25:43.524783+08', '2026-04-17 20:27:56.779614+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (23, 8, 'zh', '大清真寺', '中国历史最悠久、规模最大的清真寺之一——伊斯兰信仰与中国传统建筑风格的独特融合。', '西安大清真寺坐落于回民街的核心地带，是中国历史最悠久、最著名的清真寺之一。其最大特色在于将中国传统建筑形式——院落、亭台、牌楼——与伊斯兰宗教功能融为一体。寺院占地约一万两千平方米，由四进院落组成，礼拜大殿可容纳逾千名信众同时礼拜。', '大清真寺始建于唐玄宗天宝元年（742年），映射出西安作为丝绸之路东方起点的历史地位——数百年来，大量穆斯林商人在此定居，逐渐形成回民聚居社区。建筑群历经明清两代的重建与扩修。时至今日，这里仍是西安回族穆斯林社区的主要礼拜场所。', '非穆斯林游客可入寺参观，但须衣着端庄得体。进入礼拜大殿须脱鞋。周五主麻日及伊斯兰节日期间，寺内活动最为热闹。礼拜大殿内禁止拍照。', '2026-04-17 13:25:44.609704+08', '2026-04-17 20:28:51.603286+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (19, 7, 'en', 'Big Wild Goose Pagoda', 'A towering Tang-dynasty Buddhist pagoda that once stored sutras brought from India by the monk Xuanzang.', 'The Big Wild Goose Pagoda (Dàyàn Tǎ) is a multi-storey brick Buddhist pagoda standing 64 metres tall in the Da Ci''en Temple complex in southern Xi''an. Its seven tiers taper gracefully as they rise, embodying the elegance of Tang-dynasty architecture. The pagoda was built to house the Buddhist scriptures and artefacts that the eminent monk Xuanzang carried back from his legendary pilgrimage to India — a journey later immortalised in the classic novel Journey to the West.', 'Originally built in 652 AD under the orders of Emperor Gaozong, the pagoda was constructed in five storeys and later expanded to ten, then reduced to the present seven after earthquake damage. It has undergone several restorations through the centuries and remains an active place of Buddhist worship.', 'Climb to the top floor for panoramic views over Xi''an. The surrounding Da Ci''en Temple is a fine example of Tang Buddhist monastery architecture. The large musical fountain plaza to the north is Asia''s largest. Evenings feature a light and water show.', '2026-04-17 13:25:43.915044+08', '2026-04-17 20:28:20.432372+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (20, 7, 'zh', '大雁塔', '气势巍峨的唐代佛塔，昔日用以珍藏玄奘法师从天竺带回的梵文经典。', '大雁塔是一座位于西安南郊大慈恩寺内的多层砖制佛塔，塔高六十四米。七层塔身向上逐层收分，俊逸挺拔，是唐代建筑风格的杰出代表。此塔专为存放高僧玄奘西行求法、从古印度携返的佛经与文物而建；玄奘的这段传奇旅程后来被演绎为中国古典名著《西游记》的蓝本。', '大雁塔始建于唐高宗永徽三年（652年），初建时为五层，后扩至十层，因地震损毁后缩减为现存七层。历经多个朝代的修缮，至今仍是香火延续的佛教活动场所。', '登顶七层可俯瞰西安全城景色。周围的大慈恩寺是唐代佛教寺院建筑的精华代表。塔北的大型音乐喷泉广场据称是亚洲最大的音乐喷泉之一，夜晚有灯光水舞表演，十分壮观。', '2026-04-17 13:25:44.029596+08', '2026-04-17 20:28:20.461344+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (21, 7, 'ar', 'برج البط البري الكبير', 'صرح بوذي شاهق من عهد أسرة تانغ، احتضن يوماً الكتب المقدسة التي جلبها الراهب شيوانزانغ من الهند.', 'برج البط البري الكبير (دايان تا) صرح بوذي مشيد من الطوب يبلغ ارتفاعه 64 متراً داخل مجمع معبد داتشيان جنوبي شيان. تتناقص طوابقه السبعة بأناقة كلما ارتفعت، مجسّدةً رونق الهندسة المعمارية في عهد أسرة تانغ. شُيّد الصرح لاحتضان الكتب البوذية المقدسة والقطع الأثرية التي أحضرها الراهب الجليل شيوانزانغ من رحلة حجّه الأسطورية إلى الهند — الرحلة التي خلّدها لاحقاً الروائيُّ الكلاسيكي في "رحلة إلى الغرب".', 'شُيّد في الأصل عام 652م بأمر من الإمبراطور قاوزونغ، وكان يتألف من خمسة طوابق ثم وسّع إلى عشرة، ثم أُنقص إلى سبعة الحالية إثر أضرار زلزالية. خضع لعدة ترميمات عبر القرون ولا يزال مكان عبادة بوذياً نشطاً.', 'اصعد إلى الطابق الأعلى للاستمتاع بمناظر بانورامية على شيان. معبد داتشيان المجاور نموذج رائع لمعمار الأديرة البوذية في عهد تانغ. ساحة النافورة الموسيقية الكبرى شمالاً تُعدّ الأضخم في آسيا. تُقام أمسيات ضوء ومياه احتفالية في المساء.', '2026-04-17 13:25:44.349776+08', '2026-04-17 20:28:20.4889+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (29, 10, 'zh', '拙政园', '苏州面积最大、最负盛名的古典园林——明代园林设计精华，联合国世界遗产。', '拙政园是苏州最大的古典园林，也是中国园林艺术现存最杰出的代表之一。全园占地约五点二公顷，分东、中、西三个区域，各具不同意境。其中以中部为最精华：以开阔的荷花水池为中心，亭台楼榭若浮水面，曲折长桥横跨池上，步移景异，如诗如画。', '拙政园由明代官员王献臣于正德四年至嘉靖五年（1509—1526年）间退隐归里后所建。园名取自晋代潘岳《闲居赋》中"此亦拙者之为政也"一语，寓仕途失意而归田之意。1997年被联合国教科文组织列入世界遗产名录。', '春季（四至五月）紫藤与牡丹盛开，是游园的最佳时节。建议选择开园时间入场，可在人流高峰前尽情欣赏。拙政园与贝聿铭设计的苏州博物馆新馆相邻，可安排在同一天游览。', '2026-04-17 13:25:45.920382+08', '2026-04-17 20:22:32.486368+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (25, 9, 'en', 'Bell Tower of Xi''an', 'The symbolic centrepiece of Xi''an''s ancient grid — a magnificent Ming-dynasty tower standing at the exact crossroads of the old city.', 'The Bell Tower of Xi''an is a grand wooden structure standing at the precise geometric centre of the old city, where the four main avenues converge. Three storeys tall and 36 metres high, the tower features upturned eaves, green-glazed tiles, and intricate painted brackets. Inside, a collection of 18 replicas of Tang-dynasty bronze bells is displayed; the original ancient bell was moved to the Forest of Stone Steles Museum.', 'Originally built in 1384 during the Ming dynasty, the tower was relocated to its present site in 1582. Historically, the bell was rung at dawn each day to signal the start of the city''s activities. It served as the principal time-keeping instrument and alarm system for the city.', 'The tower is best appreciated from the surrounding roundabout. A pedestrian underpass connects the public to the entrance. In the evening, the illuminated tower is one of Xi''an''s most photogenic sights. Traditional bell-ringing performances are held daily.', '2026-04-17 13:25:44.86165+08', '2026-04-17 20:29:26.866458+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (26, 9, 'zh', '西安钟楼', '西安古城几何中心的标志——雄踞四条大街交汇处的明代木构城楼。', '西安钟楼矗立于古城四条主街的交汇正中，是一座宏伟的木构建筑。全楼三层、高三十六米，飞檐翘角、绿色琉璃瓦覆顶，彩绘斗拱精致华丽。楼内陈列着十八口唐代铜钟仿制品，原钟已移存碑林博物馆。', '钟楼始建于明洪武十七年（1384年），明神宗万历十年（1582年）迁至现址。历史上，钟楼每日清晨鸣钟，为全城报晓、统一作息，是古代西安城市运行的核心时间标志和报警系统。', '围绕钟楼转一圈是感受其整体气势的最佳方式，可从环岛四周观赏全貌。地下通道连接广场与钟楼入口。夜晚灯光下的钟楼是西安最上镜的风景之一。楼内每日均有传统鸣钟表演。', '2026-04-17 13:25:44.986573+08', '2026-04-17 20:29:26.896723+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (31, 11, 'en', 'Lion Grove Garden', 'A UNESCO-listed classical garden famed for its extraordinary labyrinth of weathered limestone rocks resembling lions.', 'Lion Grove Garden (Shīzilín) is one of the four UNESCO-listed classical gardens of Suzhou, celebrated above all for its remarkable artificial rockery — an intricate maze of weathered Taihu limestone formations said to resemble lions and other animals. The rock formations create a multi-level labyrinth of caves, tunnels, and narrow passages that visitors can explore. Surrounding the rockery are elegant pavilions, reflective ponds, and bamboo groves.', 'Built in 1342 during the Yuan dynasty by the Buddhist monk Tianru Weize and his disciples in memory of their Zen master, the garden takes its name from "Lion Rock" in Tianmu Mountain, the master''s place of origin. The garden was visited and painted by the Emperor Qianlong, who was so enchanted by it that he commissioned replicas in both the Summer Palace in Beijing and the Bishu Shanzhuang in Chengde. It was inscribed as a UNESCO World Heritage Site in 2000.', 'The rock labyrinth is a highlight — allow at least 30–45 minutes to navigate it. Children and adults alike enjoy the maze. Visit in the morning for softer light and fewer crowds. Combine with a visit to the nearby Suzhou Museum.', '2026-04-17 13:25:46.165344+08', '2026-04-17 20:23:02.696273+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (33, 11, 'ar', 'حديقة غابة الأسود', 'حديقة كلاسيكية مدرجة في قائمة اليونسكو، اشتُهرت بمتاهتها الاستثنائية من صخور الحجر الجيري المتجوية التي تُشبه الأسود.', 'حديقة غابة الأسود (شيتسيلين) إحدى الحدائق الكلاسيكية الأربع في سوتشو المدرجة في قائمة اليونسكو، وتحظى بشهرة خاصة بفضل تكوينات الصخور الصناعية الاستثنائية — متاهة معقدة من أحجار تيه الجيرية المتجوية يُقال إنها تشبه الأسود وحيوانات أخرى. تُشكّل هذه التكوينات الصخرية متاهة متعددة المستويات من الكهوف والأنفاق والممرات الضيقة التي يمكن للزوار استكشافها. تحيط بالصخور أجنحة أنيقة وبرك عاكسة وأحراش خيزران.', 'شُيّدت عام 1342م في عهد أسرة يوان على يد الراهب البوذي تيانرو وويتسي وتلاميذه تخليداً لذكرى معلمهم في تأمل الزن. تستمد تسميتها من "صخرة الأسد" في جبل تيانمو، مسقط رأس المعلم. زارها الإمبراطور تشيانلونغ ورسمها معجباً بها، فأمر بإنشاء نسختين منها في القصر الصيفي ببكين وفي بيشو شانتشوانغ في تشنغدي. أُدرجت ضمن مواقع التراث العالمي لليونسكو عام 2000م.', 'المتاهة الصخرية هي جوهر الزيارة — خصص ما لا يقل عن 30–45 دقيقة للتجوال فيها. المكان ممتع للأطفال والكبار على حد سواء. تفضّل الزيارة في الصباح للاستمتاع بإضاءة أكثر نعومة وعدد أقل من الزوار. يمكن تنسيق الزيارة مع متحف سوتشو القريب.', '2026-04-17 13:25:46.416693+08', '2026-04-17 20:23:02.764975+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (34, 12, 'en', 'Lingering Garden', 'A masterpiece of classical Chinese garden design, celebrated for its unusual rock formations, intricate corridors, and serene courtyards.', 'Lingering Garden (Liú Yuán) is one of the four UNESCO-listed classical gardens of Suzhou, praised for its exceptional spatial variety and the extraordinary quality of its design. The garden is divided into four sections — central, eastern, western, and northern — each showcasing a different design language. Its most prized feature is a 6.5-metre-tall Taihu limestone rock named "Crown of Clouds Peak" (Guanyunfeng), considered the finest specimen of rock art in all of Suzhou''s gardens. The garden''s covered walkway system — over 700 metres in total — seamlessly connects all areas.', 'Originally built during the Ming dynasty in 1593 by Xu Taishi, the garden fell into disrepair and was renovated and enlarged during the Qing dynasty by Liu Rong, after whom the garden is named. It was inscribed as a UNESCO World Heritage Site in 1997.', 'The covered walkway offers protection from rain and sun — a great choice in all weathers. Take time in the eastern section''s courtyards, which demonstrate the finest Suzhou interior spatial design. Audio guides explain the symbolism of each rock and pavilion.', '2026-04-17 13:25:46.534584+08', '2026-04-17 20:23:49.030824+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (35, 12, 'zh', '留园', '中国古典园林设计的杰作，以奇峰怪石、回廊曲折、院落幽深著称。', '留园是苏州四大世界遗产古典园林之一，以空间层次丰富、设计品质卓越著称。全园分为中、东、西、北四个区域，各区设计语言迥异。园中最珍贵的藏品是一块高六点五米的太湖石，名曰"冠云峰"，被誉为苏州诸园太湖石中的极品。全园回廊总长逾七百米，将各区域巧妙串联为一个整体。', '留园由明代徐泰时于万历二十一年（1593年）所建，后荒废。清代刘蓉峰购地重修并大加扩建，园因此而得名"刘园"，后改称"留园"。1997年被联合国教科文组织列入世界遗产名录。', '全程回廊设计可遮风避雨，无论晴雨皆宜游览。东区庭院充分展现了苏州传统室内空间设计的最高境界，值得放慢脚步细细品味。语音导览可帮助了解各峰石与亭台所蕴含的文化寓意。', '2026-04-17 13:25:46.650088+08', '2026-04-17 20:23:49.059795+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (36, 12, 'ar', 'حديقة المتسكع', 'تحفة في تصميم الحدائق الصينية الكلاسيكية، تشتهر بتكوينات صخرية غريبة وممرات متشعبة وأفنية هادئة.', 'حديقة المتسكع (ليو يوان) إحدى الحدائق الكلاسيكية الأربع في سوتشو المدرجة في قائمة اليونسكو، وتُشاد بتنوعها الفضائي الاستثنائي وجودة تصميمها الرفيعة. تنقسم إلى أربعة أقسام — وسطي وشرقي وغربي وشمالي — يعرض كلٌّ منها أسلوباً تصميمياً مختلفاً. أبرز معالمها صخرة من أحجار تيه الجيرية ارتفاعها 6.5 أمتار تُسمى "قمة التاج السحابي" (قوانيونفنغ)، وتُعدّ أرقى عينة من فن الصخور في جميع حدائق سوتشو. يبلغ نظام الممرات المسقوفة في الحديقة أكثر من 700 متر، مؤلفاً جميع المناطق بسلاسة.', 'شُيّدت في الأصل خلال أسرة مينغ عام 1593م على يد شيو تايشي، ثم أُهملت وأُعيد ترميمها وتوسيعها في عهد أسرة تشينغ على يد ليو رونغ الذي سُمّيت باسمه. أُدرجت ضمن مواقع التراث العالمي لليونسكو عام 1997م.', 'الممرات المسقوفة توفر حمايةً من المطر والشمس — خيار ممتاز في جميع الأحوال الجوية. خذ وقتاً كافياً في أفنية القسم الشرقي التي تُظهر أرقى أشكال التصميم الفضائي الداخلي السوتشوي. المرشدات الصوتية تشرح رمزية كل صخرة وجناح.', '2026-04-17 13:25:46.769549+08', '2026-04-17 20:23:49.102482+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (7, 3, 'en', 'Summer Palace', 'An imperial garden of unrivalled beauty, centred on the vast Kunming Lake and Longevity Hill.', 'The Summer Palace is China''s largest and best-preserved imperial garden, stretching across 2.9 square kilometres. Its centrepiece, Kunming Lake, occupies three-quarters of the total area, while Longevity Hill rises dramatically from the northern shore, crowned by the resplendent Tower of the Fragrance of the Buddha. Covered walkways, ornate pavilions, and marble bridges complete this vision of idealised nature.', 'Originally constructed in 1750 by Emperor Qianlong as a gift for his mother''s 60th birthday, the garden was largely destroyed by Anglo-French forces in 1860 and later rebuilt by Empress Dowager Cixi in 1886, partly using naval funds. It was inscribed as a UNESCO World Heritage Site in 1998.', 'Take a boat ride on Kunming Lake for the best views of Longevity Hill. The long covered corridor (728 metres) is a highlight. Visit in spring for cherry blossoms or winter for icy lake scenery.', '2026-04-17 13:25:41.569467+08', '2026-04-17 20:10:08.522063+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (9, 3, 'ar', 'القصر الصيفي', 'حديقة إمبراطورية لا مثيل لها في جمالها، تتمحور حول بحيرة كونمينغ الشاسعة وتلة الخلود.', 'القصر الصيفي أكبر حديقة إمبراطورية صينية وأكثرها اكتمالاً وصوناً، وتمتد على مساحة 2.9 كيلومتر مربع. تحتل بحيرة كونمينغ ثلاثة أرباع المساحة الإجمالية، فيما تعلو تلة الخلود بشموخ من الشاطئ الشمالي متوّجةً ببرج عطر البوذا الرائع. تُكمّل الممرات المسقوفة والأجنحة المزخرفة والجسور الرخامية هذا المشهد الطبيعي المثالي.', 'شُيّد في الأصل عام 1750م بأمر من الإمبراطور تشيانلونغ هدية لأمه بمناسبة عيد ميلادها الستين. دمّرته إلى حد بعيد القوات الأنجلو-فرنسية عام 1860م، ثم أعادت بناءه الإمبراطورة الأرملة تسيشي عام 1886م باستخدام جزء من ميزانية البحرية. أُدرج ضمن مواقع التراث العالمي لليونسكو عام 1998م.', 'اركب قارباً في بحيرة كونمينغ للاستمتاع بأجمل مناظر تلة الخلود. الممر المسقوف الطويل (728 متراً) أبرز معالم الحديقة. زيارتها في الربيع لمشاهدة أزهار الكرز أو في الشتاء لمشاهدة البحيرة المجمدة كلتاهما تجربة لا تُنسى.', '2026-04-17 13:25:41.812216+08', '2026-04-17 20:10:08.591318+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (13, 5, 'en', 'Great Wall — Badaling', 'The most visited section of the Great Wall, offering sweeping views across forested ridgelines north of Beijing.', 'The Badaling section of the Great Wall is the most famous and best-restored stretch of this iconic structure, located approximately 70 km north of central Beijing. Running along dramatic ridgelines through rugged mountainous terrain, the wall at Badaling stands 7.8 metres high and 6 metres wide at the top. Watchtowers are positioned every 100–200 metres, each once manned by garrison soldiers tasked with signalling and defence.', 'The Great Wall was built across multiple dynasties, with the Badaling section dating to the Ming dynasty (1368–1644). The wall originally stretched over 21,000 kilometres across northern China, serving as the empire''s primary northern defensive barrier against nomadic incursions. Badaling was the first section opened to foreign dignitaries and tourists in 1957.', 'Book tickets in advance online. Weekends and public holidays are extremely crowded. The North 8 section offers steeper, more dramatic climbing with fewer crowds. Wear comfortable walking shoes.', '2026-04-17 13:25:42.314799+08', '2026-04-17 20:11:56.840723+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (15, 5, 'ar', 'سور الصين العظيم — بادالينغ', 'أكثر أقسام سور الصين العظيم ارتياداً، يُطل على مناظر خلابة من التلال الحرجية شمال بكين.', 'يُعدّ قسم بادالينغ من سور الصين العظيم أشهر امتداداته وأفضلها ترميماً وصوناً، ويقع على بعد نحو 70 كيلومتراً شمال وسط بكين. يمتد السور على طول سلاسل جبلية شاهقة في تضاريس وعرة، ويبلغ ارتفاعه في بادالينغ 7.8 أمتار وعرض أعلاه 6 أمتار. تتوزع الأبراج المراقبة كل 100–200 متر، وكانت تُوكَل إلى حراس عسكريين مهمة الإشارة والدفاع.', 'شُيّد السور الكبير عبر أسرات حاكمة متعاقبة، ويعود قسم بادالينغ إلى عهد أسرة مينغ (1368–1644م). امتد السور في الأصل أكثر من 21,000 كيلومتر عبر شمال الصين، وكان الحاجزَ الدفاعي الرئيسي ضد الغزوات البدوية الشمالية. افتُتح بادالينغ عام 1957م بوصفه أول قسم يُفتح أمام الشخصيات الأجنبية والسياح.', 'احجز تذاكرك مسبقاً عبر الإنترنت. أيام العطل الأسبوعية والرسمية تشهد ازدحاماً شديداً. يوفر قسم الشمال 8 تسلقاً أكثر حدة ومناظر أكثر روعة مع عدد أقل من الزوار. ارتدِ حذاءً مريحاً للمشي.', '2026-04-17 13:25:43.279889+08', '2026-04-17 20:11:56.899558+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (28, 10, 'en', 'Humble Administrator''s Garden', 'Suzhou''s largest and most celebrated classical garden — a UNESCO World Heritage Site of exquisite Ming-dynasty design.', 'The Humble Administrator''s Garden (Zhuōzhèng Yuán) is the largest classical garden in Suzhou and one of the finest examples of Chinese landscape gardening in existence. Covering 5.2 hectares, it is divided into three sections — eastern, central, and western — each with a distinct character. The garden''s central section, centred on a large lotus pond, is the most celebrated: pavilions appear to float on water, zigzag bridges traverse the pond, and carefully framed views create painterly compositions at every turn.', 'The garden was originally built between 1509 and 1526 by Wang Xianchen, a retired imperial official, after his return from Beijing. Its name derives from a line of poetry by Pan Yue of the Jin dynasty: "to administer water and cultivate plants — this is also the affair of the humble administrator." It was listed as a UNESCO World Heritage Site in 1997.', 'Spring (April–May) is the most beautiful time to visit, when wisteria and peonies are in bloom. Arrive at opening time to enjoy the garden before crowds gather. The garden connects to the Suzhou Museum (designed by I.M. Pei) — visit both in one trip.', '2026-04-17 13:25:45.804664+08', '2026-04-17 20:22:32.457761+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (3, 1, 'ar', 'المدينة المحرمة', 'أكبر قصر إمبراطوري محفوظ في العالم، شهد إقامة 24 إمبراطوراً خلال أسرتَي مينغ وتشينغ.', 'المدينة المحرمة — المعروفة بالصينية بـ"قوقونغ" (故宫) — مجمع قصور شاسع يقع في قلب بكين. تمتد على مساحة 720,000 متر مربع وتضم 980 مبنى لا تزال قائمة، وقد ظلت المركزَ الحكومي الإمبراطوري في الصين قرابة خمسة قرون. تُضفي الأسقفُ الذهبية الألوان والجدرانُ القرمزية الزاهية والبواباتُ الشاهقة جلالاً إمبراطورياً لا يُضاهى.', 'بدأ تشييده عام 1406م في عهد الإمبراطور يونغلي من أسرة مينغ، واكتمل عام 1420م بمشاركة أكثر من مليون عامل وما يزيد على 100,000 حرفي ماهر. صُنِّف موقعاً للتراث العالمي لليونسكو عام 1987م، ويضم اليوم متحف القصر الذي يُعدّ من أكثر المؤسسات الثقافية ارتياداً في الصين.', 'ابدأ زيارتك مبكراً لتجنب الازدحام. يُغلق القصر أيام الاثنين. خصص ما لا يقل عن 3–4 ساعات لجولتك. تتوفر مرشدات صوتية بلغات متعددة عند البوابة الرئيسية.', '2026-04-17 13:25:40.189599+08', '2026-04-17 23:06:31.178487+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (30, 10, 'ar', 'حديقة المسؤول المتواضع', 'أكبر حدائق سوتشو الكلاسيكية وأشهرها — موقع تراث عالمي لليونسكو من تصميم أسرة مينغ الرفيع.', 'حديقة المسؤول المتواضع (تشوو تشنغ يوان) أكبر الحدائق الكلاسيكية في سوتشو وأحد أبرز نماذج فن تصميم الحدائق الصيني على الإطلاق. تمتد على 5.2 هكتار، وتنقسم إلى ثلاثة أقسام — شرقي ووسطي وغربي — يتميز كل منها بطابع مختلف. يُعدّ القسم الوسطي المتمحور حول بركة الزنابق الكبيرة الأبهى شأناً: إذ تبدو الأجنحة وكأنها تطفو على الماء، وتعبر الجسور المتعرجة البركة، وتُشكّل المشاهد المؤطرة بعناية لوحات تصويرية عند كل منعطف.', 'شُيّدت الحديقة في الأصل بين عامَي 1509م و1526م على يد وانغ شيانتشن، مسؤول إمبراطوري متقاعد، بعد عودته من بكين. يستمد اسمها من بيت شعر للشاعر بان يوي من عهد جين: "إدارة المياه وزراعة النباتات — هذا أيضاً شأن المسؤول المتواضع." أُدرجت ضمن مواقع التراث العالمي لليونسكو عام 1997م.', 'الربيع (أبريل–مايو) أجمل فصول الزيارة حين تتفتح أزهار الوستريا والفاوانيا. احرص على الوصول عند الافتتاح للتمتع بالحديقة قبل اكتظاظها. تتجاور الحديقة مع متحف سوتشو (من تصميم المعماري إي. إم. باي) — يمكن زيارة الاثنين في يوم واحد.', '2026-04-17 13:25:46.044922+08', '2026-04-17 20:22:32.530735+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (32, 11, 'zh', '狮子林', '联合国世界遗产古典园林，以形态各异、宛如狮群的天然太湖石假山迷宫闻名于世。', '狮子林是苏州四大世界遗产古典园林之一，以园内奇特的假山迷宫享誉四方——大量经天然风化的太湖石形态嶙峋，据说貌似狮子及各种动物。太湖石堆叠而成的山体中，洞穴、隧道与幽径纵横交错，构成立体迷宫，令游客流连探索。假山四周配以精巧亭台、清澈水池与翠竹丛林。', '狮子林建于元至正二年（1342年），由高僧天如惟则与弟子们为纪念其禅宗师父而建，园名取自师父得法处天目山的"狮子岩"。清乾隆皇帝六次下江南，多次亲临并挥毫作画，深为倾慕，曾分别在北京颐和园和承德避暑山庄仿建狮子林。2000年被联合国教科文组织列入世界遗产名录。', '假山迷宫是全园最精彩的部分，建议预留至少三十至四十五分钟慢慢探索。大人小孩都会对迷宫乐此不疲。清晨光线柔和且人少，是参观佳时。可与附近苏州博物馆连同游览。', '2026-04-17 13:25:46.299743+08', '2026-04-17 20:23:02.736839+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (18, 6, 'ar', 'سور مدينة شيان', 'أكمل سور مدينة قديم في الصين — تحصين من عهد أسرة مينغ يمتد 13.74 كيلومتراً لا يزال يحيط بالمدينة القديمة.', 'سور مدينة شيان إنجاز رائع من إنجازات الهندسة العسكرية في عهد أسرة مينغ (1370م)، يشكّل مستطيلاً شبه مكتمل يلتف حول مركز المدينة القديمة. يبلغ ارتفاعه 12 متراً، وعرض قاعدته 15–18 متراً، ومحيطه الكلي 13.74 كيلومتراً، مما يجعله أكمل سور مدينة قديم في الصين. يضم السور 98 شُرفة دفاعية، و4 بوابات رئيسية، و4 أبراج مراقبة، وخندق دفاعي. يتيح السور اليوم للزوار التجوّل سيراً أو ركوباً للدراجة على طول قمته الفسيحة المستوية.', 'شُيّد السور الراهن على أساسات سور المدينة الإمبراطورية من عهد أسرة تانغ التي يعود تاريخها إلى عام 618م. اكتمل تشييد سور مينغ عام 1370م في عهد الإمبراطور هونغووو. استُخدم في بنائه أسلوب ثوري: ملاط من الأرز اللزج الممزوج بالجير، وقد أثبت هذا الخليط متانةً استثنائية — إذ لا تزال أقسام منه صامدة بعد 650 عاماً.', 'يُنصح بشدة باستئجار دراجة هوائية للتجوّل في المحيط الكامل (13.74 كيلومتراً، نحو 1.5–2 ساعة). يتزين السور بإضاءة خلابة في الليل. بوابة الجنوب (يونغنينغ) هي المدخل الرئيسي والأكثر فخامة.', '2026-04-17 13:25:43.647205+08', '2026-04-17 20:27:56.807285+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (22, 8, 'en', 'Great Mosque of Xi''an', 'One of China''s oldest and largest mosques — a unique fusion of Islamic faith and traditional Chinese architecture.', 'The Great Mosque of Xi''an is one of the oldest and most celebrated mosques in China, located in the heart of the Muslim Quarter (Huimin Street). Uniquely, it merges traditional Chinese architectural forms — courtyards, pavilions, decorated gateways — with Islamic religious function. The mosque covers 12,000 square metres across four successive courtyards, and its prayer hall can accommodate more than 1,000 worshippers.', 'Founded in 742 AD during the Tang dynasty, the mosque reflects Xi''an''s historic role as the eastern terminus of the Silk Road, where a substantial Muslim community settled over centuries of trade. The complex was rebuilt and enlarged during the Ming and Qing dynasties. It remains an active mosque serving Xi''an''s Hui Muslim community today.', 'Non-Muslim visitors are welcome but must dress modestly. Remove shoes before entering the prayer hall. The mosque is particularly vibrant during Friday prayers and Islamic festivals. Photography in the prayer hall is not permitted.', '2026-04-17 13:25:44.479742+08', '2026-04-17 20:28:51.574163+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (24, 8, 'ar', 'المسجد الكبير في شيان', 'أحد أقدم المساجد وأضخمها في الصين — مزيج فريد بين الإيمان الإسلامي والعمارة الصينية التقليدية.', 'المسجد الكبير في شيان من أقدم المساجد وأعرقها في الصين، ويقع في قلب الحي الإسلامي (شارع هويمين). يتميز بطريقة فريدة تمزج فيها العمارةُ الصينية التقليدية — من فناءات وأجنحة وبوابات مزخرفة — مع الوظيفة الدينية الإسلامية. يمتد المسجد على 12,000 متر مربع عبر أربعة أفنية متتالية، وقاعة صلاته تتسع لأكثر من ألف مصلٍّ.', 'تأسس عام 742م في عهد أسرة تانغ، ويعكس الدور التاريخي لشيان بوصفها الطرف الشرقي لطريق الحرير، حيث استوطنت جالية مسلمة كبيرة على مدى قرون من التجارة. رُمّم المجمع وجُدّد ووسّع في عهد أسرتَي مينغ وتشينغ. ولا يزال مسجداً نشطاً يخدم مجتمع مسلمي الهوي في شيان حتى اليوم.', 'يُرحَّب بالزوار من غير المسلمين مع ضرورة التزام اللباس المحتشم. انزع حذاءك قبل دخول قاعة الصلاة. المسجد في أبهى حيوية خلال صلاة الجمعة والأعياد الإسلامية. التصوير داخل قاعة الصلاة غير مسموح به.', '2026-04-17 13:25:44.737012+08', '2026-04-17 20:28:51.643137+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (27, 9, 'ar', 'برج الأجراس في شيان', 'المحور الرمزي لشبكة شيان القديمة — برج رائع من عهد أسرة مينغ يقف عند تقاطع الطرق الرئيسية بالضبط في المدينة العتيقة.', 'برج الأجراس في شيان هيكل خشبي ضخم يقف في المركز الهندسي الدقيق للمدينة القديمة، حيث تلتقي الشوارع الرئيسية الأربعة. يبلغ ارتفاعه 36 متراً على ثلاثة طوابق، تتميز بتقاطعات سقف منحنية الحواف وبلاط مطلي بالخزف الأخضر وأعمدة دعم مزخرفة بدقة. يعرض الداخل 18 نسخة طبق الأصل من أجراس نحاسية من عهد تانغ؛ أما الجرس القديم الأصلي فنُقل إلى متحف غابة اللوحات الحجرية.', 'شُيّد في الأصل عام 1384م خلال أسرة مينغ، ثم نُقل إلى موقعه الحالي عام 1582م. تاريخياً، كان الجرس يُقرع عند الفجر يومياً إيذاناً ببدء نشاطات المدينة، وكان يُمثّل الأداةَ الرئيسية لقياس الوقت ونظام الإنذار في المدينة.', 'يُدرك البرج بأفضل صورة من الدوّار المحيط به. ممر مشاة تحت الأرض يربط العامة بالمدخل. في المساء، يُعدّ البرج المضاء من أجمل المشاهد التصويرية في شيان. تُقام عروض قرع الأجراس التقليدية يومياً.', '2026-04-17 13:25:45.67469+08', '2026-04-17 20:29:26.926856+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (1, 1, 'en', 'Forbidden City', 'The world''s largest preserved imperial palace, home to 24 emperors across the Ming and Qing dynasties.', 'The Forbidden City — known in Chinese as Gùgōng (故宫) — is a colossal palace complex at the heart of Beijing. Covering 720,000 square metres and comprising 980 surviving buildings, it served as the ceremonial and political centre of Chinese government for nearly five centuries. Its sweeping golden rooftiles, vivid vermilion walls, and towering gatehouses create an architecture of overwhelming imperial grandeur.', 'Construction began in 1406 under the Yongle Emperor of the Ming dynasty and was completed in 1420, employing over one million labourers and 100,000 skilled craftsmen. The complex was designated a UNESCO World Heritage Site in 1987 and now houses the Palace Museum, one of China''s most visited cultural institutions.', 'Arrive early to beat the crowds. The palace is closed on Mondays. Allow at least 3–4 hours. Audio guides are available in multiple languages at the main gate.', '2026-04-17 13:25:39.91451+08', '2026-04-17 23:06:31.106679+08');
INSERT INTO "public"."landmark_translations" ("id", "landmark_id", "language", "name", "short_description", "description", "historical_background", "visiting_tips", "created_at", "updated_at") VALUES (6, 2, 'ar', 'معبد السماء', 'مجمع فخم من الأضرحة الإمبراطورية حيث كان الأباطرة يصلّون طلباً لمحاصيل وافرة — موقع تراث عالمي لليونسكو.', 'معبد السماء تحفةٌ معمارية دينية من عهد أسرة مينغ، تحتضنه متنزه رحيب ساكن في جنوب بكين. قاعة الصلاة من أجل حصاد جيد بأسقفها الثلاثية المبلطة باللون الأزرق من أبرز الرموز المعمارية في الصين. يشمل المجمع أيضاً مذبح التل الدائري وقبة السماء الإمبراطورية، وتربطها جميعاً جسر دانبي المرتفع.', 'شُيّد بين عامَي 1406م و1420م، ووسّعه الإمبراطور جياجينغ عام 1530م. كان يستضيف مراسم تقديم القرابين للسماء مرتين سنوياً، يتوسل فيها الإمبراطور بوصفه "ابن السماء" طلباً لمحاصيل وافرة. أُدرج ضمن مواقع التراث العالمي لليونسكو عام 1998م.', 'المتنزه المحيط بالمعبد ملتقى محبوب للسكان المحليين، لا سيما في الصباح الباكر. تفضّل الزيارة في أيام الأسبوع للحصول على تجربة أكثر هدوءاً. أجمل مناظر قاعة الصلاة تُرى من الجانب الجنوبي.', '2026-04-17 13:25:41.444773+08', '2026-04-17 23:07:27.198924+08');
COMMIT;

-- ----------------------------
-- Table structure for landmarks
-- ----------------------------
DROP TABLE IF EXISTS "public"."landmarks";
CREATE TABLE "public"."landmarks" (
  "id" int4 NOT NULL DEFAULT nextval('landmarks_id_seq'::regclass),
  "city_id" int4 NOT NULL,
  "slug" varchar(100) COLLATE "pg_catalog"."default" NOT NULL,
  "latitude" numeric(10,7) NOT NULL,
  "longitude" numeric(10,7) NOT NULL,
  "category" varchar(50) COLLATE "pg_catalog"."default" NOT NULL,
  "featured_image" varchar(500) COLLATE "pg_catalog"."default",
  "is_featured" bool NOT NULL DEFAULT false,
  "sort_order" int2 NOT NULL DEFAULT 0,
  "is_active" bool NOT NULL DEFAULT true,
  "created_at" timestamptz(6) NOT NULL DEFAULT now(),
  "updated_at" timestamptz(6) NOT NULL DEFAULT now()
)
;
ALTER TABLE "public"."landmarks" OWNER TO "shenyefan";

