-- ----------------------------
-- Table structure for reviews
-- ----------------------------
DROP TABLE IF EXISTS "public"."reviews";
CREATE TABLE "public"."reviews" (
  "id" int4 NOT NULL DEFAULT nextval('reviews_id_seq'::regclass),
  "user_id" int4,
  "city_id" int4,
  "author_name" varchar(100) COLLATE "pg_catalog"."default" NOT NULL,
  "content" text COLLATE "pg_catalog"."default" NOT NULL,
  "rating" int2,
  "status" varchar(20) COLLATE "pg_catalog"."default" NOT NULL DEFAULT 'pending'::character varying,
  "created_at" timestamptz(6) NOT NULL DEFAULT now(),
  "updated_at" timestamptz(6) NOT NULL DEFAULT now()
)
;
ALTER TABLE "public"."reviews" OWNER TO "shenyefan";

-- ----------------------------
-- Records of reviews
-- ----------------------------
BEGIN;
INSERT INTO "public"."reviews" ("id", "user_id", "city_id", "author_name", "content", "rating", "status", "created_at", "updated_at") VALUES (1, 2, 1, 'James Davidson', 'Walking through the Forbidden City felt like stepping back 600 years in time. The sheer scale and detail of the architecture left me speechless.', 5, 'approved', '2026-04-17 14:15:03.992924+08', '2026-04-17 14:15:03.992924+08');
INSERT INTO "public"."reviews" ("id", "user_id", "city_id", "author_name", "content", "rating", "status", "created_at", "updated_at") VALUES (2, 3, 2, 'Maria Kovács', 'The Terracotta Army in Xi''an is unlike anything I''ve ever seen. Each warrior has a unique face — it''s a miracle of ancient craftsmanship.', 5, 'approved', '2026-04-17 14:15:04.152996+08', '2026-04-17 14:15:04.152996+08');
INSERT INTO "public"."reviews" ("id", "user_id", "city_id", "author_name", "content", "rating", "status", "created_at", "updated_at") VALUES (3, 4, 3, 'Anna Laurent', 'Suzhou''s classical gardens are pure serenity. Every pavilion, every rock, every pond is placed with centuries of artistic intention.', 5, 'approved', '2026-04-17 14:15:04.278135+08', '2026-04-17 14:15:04.278135+08');
COMMIT;

